class NoisyInfoFilter(logging.Filter):
    """Drop extremely chatty INFO logs unless explicitly enabled."""

    _noisy_prefixes = (
        "[RAW_PROC]",
        "[GALLERY]",
        "[DISPLAY]",
        "[DISPLAY_PIXMAP]",
        "[LOAD]",
        "[VIEW_MODE]",
        "[WINDOW_RESIZE]",
        "[PERF]",
    )

    def __init__(self, enabled: bool):
        super().__init__()
        self.enabled = enabled

    def filter(self, record: logging.LogRecord) -> bool:
        if self.enabled:
            return True
        if record.levelno != logging.INFO:
            return True
        msg = record.getMessage()
        return not msg.startswith(self._noisy_prefixes)


class FocusGallerySwitchFilter(logging.Filter):
    """Keep only gallery-switch related logs (plus warnings/errors)."""

    _allow_prefixes = (
        "[MODESWITCH]",
        "[VIEW_MODE]",
        "[GALLERY]",
        "[FOLDER]",
        "[MAIN]",
        "[ACCEL]",
        "[INDEX]",
        "[LOAD]",
        "[TTFR]",
        "[MANAGER]",
        "[SHARE]",
        "[CLOSE]",
        "[PROFILE]",
    )

    def filter(self, record: logging.LogRecord) -> bool:
        # Always keep warnings/errors for troubleshooting.
        if record.levelno >= logging.WARNING:
            return True
        msg = record.getMessage()
        return msg.startswith(self._allow_prefixes)


def setup_logging():
    """Setup logging configuration with file and console handlers"""
    try:
        # Honor --file-log before anything treats argv as a photo path.
        if _consume_file_log_argv():
            os.environ["RAWVIEWER_FILE_LOG"] = "1"
            os.environ.setdefault("RAWVIEWER_VERBOSE_INFO_LOGS", "1")
            os.environ.setdefault("RAWVIEWER_FOCUS_GALLERY_SWITCH", "1")
            os.environ.setdefault("RAWVIEWER_REDIRECT_STDIO", "1")
            os.environ.setdefault("RAWVIEWER_FATAL_DUMP", "1")

        # Configure logging
        log_format = '%(asctime)s - %(levelname)s - [%(name)s:%(lineno)d] - %(message)s'
        date_format = '%Y-%m-%d %H:%M:%S'
        
        # Create formatters
        formatter = logging.Formatter(log_format, date_format)

        # Configure root logger
        root_logger = logging.getLogger()
        root_logger.setLevel(logging.DEBUG)
        
        # Clear any existing handlers to avoid duplicates
        root_logger.handlers.clear()

        # Always attach a console/stream handler when possible.
        stream = sys.stdout if sys.stdout is not None else getattr(sys, "__stdout__", None)
        focus_gallery_switch = _env_true("RAWVIEWER_FOCUS_GALLERY_SWITCH", default=False)
        is_dev = os.environ.get("RAWVIEWER_DEBUG", "").strip() in ("1", "true", "True", "YES", "yes")
        
        verbose_info = _env_true("RAWVIEWER_VERBOSE_INFO_LOGS", default=False) or focus_gallery_switch or is_dev
        
        if stream is not None:
            console_handler = logging.StreamHandler(stream)
            if is_dev:
                console_handler.setLevel(logging.DEBUG)
            else:
                console_handler.setLevel(logging.INFO)
            console_handler.setFormatter(formatter)
            console_handler.addFilter(NoisyInfoFilter(verbose_info))
            if focus_gallery_switch:
                console_handler.addFilter(FocusGallerySwitchFilter())
            root_logger.addHandler(console_handler)
        else:
            # Windowed builds can have no stdout; keep logging silent unless file logging is enabled.
            root_logger.addHandler(logging.NullHandler())

        # File logging: explicit opt-in only (RAWVIEWER_FILE_LOG / --file-log /
        # enable_debug_log marker). Never auto-write session logs for privacy
        # and disk size — console/stream handlers remain for interactive runs.
        enable_file_log = _file_logging_requested()

        if enable_file_log:
            log_dir = _runtime_log_dir()
            os.makedirs(log_dir, exist_ok=True)

            timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
            log_file = os.path.join(log_dir, f'rawviewer_{timestamp}.log')
            latest_file = os.path.join(log_dir, 'rawviewer_latest.log')

            file_handler = logging.FileHandler(log_file, encoding='utf-8', mode='w')
            file_handler.setLevel(logging.DEBUG)
            file_handler.setFormatter(formatter)
            file_handler.addFilter(NoisyInfoFilter(verbose_info))
            if focus_gallery_switch:
                file_handler.addFilter(FocusGallerySwitchFilter())
            root_logger.addHandler(file_handler)

            # Easy-to-find alias for support: always the current session.
            try:
                latest_handler = logging.FileHandler(
                    latest_file, encoding='utf-8', mode='w'
                )
                latest_handler.setLevel(logging.DEBUG)
                latest_handler.setFormatter(formatter)
                latest_handler.addFilter(NoisyInfoFilter(verbose_info))
                if focus_gallery_switch:
                    latest_handler.addFilter(FocusGallerySwitchFilter())
                root_logger.addHandler(latest_handler)
            except OSError:
                latest_file = None

            root_logger.info("[LOG] File logging enabled: %s", log_file)
            if latest_file:
                root_logger.info("[LOG] Latest session alias: %s", latest_file)
            return log_file

        return None
        
    except Exception as e:
        # If logging setup fails, at least print to stderr
        error_msg = f"CRITICAL: Failed to setup logging: {e}"
        safe_print_err(error_msg)
        import traceback
        safe_print_err(f"Traceback: {traceback.format_exc()}")
        
        # Try to write to a fallback log file
        try:
            # Only attempt fallback file logging if explicitly enabled.
            if _file_logging_requested():
                fallback_log = os.path.join(_runtime_log_dir(), 'error.log')
                os.makedirs(os.path.dirname(fallback_log), exist_ok=True)
                with open(fallback_log, 'a', encoding='utf-8') as f:
                    f.write(f"{datetime.now().strftime('%Y-%m-%d %H:%M:%S')} - {error_msg}\n")
                    f.write(f"{traceback.format_exc()}\n")
        except Exception:
            pass  # If even fallback fails, we've done our best
        
        raise  # Re-raise to let caller handle it


def global_exception_handler(exc_type, exc_value, exc_traceback):
    """Handle uncaught exceptions and write them to a crash report log file."""
    import traceback
    import logging
    from datetime import datetime

    # Format the traceback
    try:
        tb_text = "".join(traceback.format_exception(exc_type, exc_value, exc_traceback))
    except Exception:
        tb_text = f"{exc_type}: {exc_value}\n(logging traceback failed)\n"

    # Try logging via the standard logger first (filters can recurse on some errors).
    try:
        logger = logging.getLogger(__name__)
        logger.critical("Uncaught Exception:\n" + tb_text)
    except Exception:
        safe_print_err("Uncaught Exception:\n" + tb_text)
    
    # Write to a persistent crash report file in LocalAppData
    try:
        log_dir = _runtime_log_dir()
        os.makedirs(log_dir, exist_ok=True)
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        crash_file = os.path.join(log_dir, f'crash_report_{timestamp}.txt')
        with open(crash_file, "w", encoding="utf-8") as f:
            f.write(f"RAWviewer Crash Report - {timestamp}\n")
            f.write("="*50 + "\n\n")
            f.write(tb_text)
    except Exception as e:
        safe_print_err(f"Could not write crash report file: {e}")

    # Fall back to default behavior
    sys.__excepthook__(exc_type, exc_value, exc_traceback)

# Set the global exception handler
sys.excepthook = global_exception_handler


def _filmstrip_ui_env_int(name: str, default: int, *, minimum: int = 0) -> int:
    try:
        return max(minimum, int(os.environ.get(name, str(default)).strip()))
    except (TypeError, ValueError):
        return default


def _windows_shell_verb_suggests_share(verb_name: object) -> bool:
    """Match Explorer context-menu verbs for 'Share' across English and common locales."""
    s = str(verb_name or "")
    low = s.replace("&", "").strip().lower()
    if "share" in low or "windows.share" in low:
        return True
    plain = s.replace("&", "")
    for token in (
        "\u5171\u7528",  # zh-TW: 共用
        "\u5206\u4eab",  # zh-CN: 分享
        "partage",
        "teilen",
        "condividi",
        "compartir",
        "delen",
    ):
        if token in plain or token in low:
            return True
    return False


def _open_windows_open_with_dialog(path: str, owner_hwnd: int = 0) -> bool:
    """Show the native Windows 'Open with' dialog for a file."""
    import subprocess
    from ctypes import Structure, byref, c_long, wintypes

    abs_path = os.path.abspath(path)
    if not os.path.isfile(abs_path):
        return False

    hwnd = int(owner_hwnd or 0)
    OAIF_EXEC = 0x0004  # Required on Win10+ or Windows shows "go to Settings" instead.

    # Classic Open With picker (Unicode). Prefer this over SHOpenWithDialog on Win11.
    try:
        shell32 = ctypes.windll.shell32
        shell32.OpenAs_RunDLLW.argtypes = [
            wintypes.HWND,
            wintypes.HINSTANCE,
            wintypes.LPCWSTR,
            ctypes.c_int,
        ]
        shell32.OpenAs_RunDLLW.restype = None
        shell32.OpenAs_RunDLLW(hwnd, None, abs_path, 1)
        return True
    except Exception:
        pass

    # SHOpenWithDialog — must pass OAIF_EXEC or user only sees the Settings redirect.
    try:
        class _OPENASINFO(Structure):
            _fields_ = [
                ("pcszFile", wintypes.LPCWSTR),
                ("pcszClass", wintypes.LPCWSTR),
                ("oaifInFlags", wintypes.DWORD),
            ]

        shell32 = ctypes.windll.shell32
        shell32.SHOpenWithDialog.argtypes = [wintypes.HWND, ctypes.POINTER(_OPENASINFO)]
        shell32.SHOpenWithDialog.restype = c_long
        info = _OPENASINFO(abs_path, None, OAIF_EXEC)
        hr = int(shell32.SHOpenWithDialog(hwnd, byref(info)))
        if hr >= 0:
            return True
    except Exception:
        pass

    # rundll32 fallback — must use OpenAs_RunDLLW, not the ANSI OpenAs_RunDLL.
    try:
        subprocess.Popen(["rundll32.exe", "shell32.dll,OpenAs_RunDLLW", abs_path])
        return True
    except Exception:
        pass

    try:
        flags = 0
        if hasattr(subprocess, "CREATE_NO_WINDOW"):
            flags = subprocess.CREATE_NO_WINDOW  # type: ignore[attr-defined]
        r = subprocess.run(
            [
                "powershell",
                "-NoProfile",
                "-Sta",
                "-Command",
                "Start-Process",
                "-FilePath",
                abs_path,
                "-Verb",
                "OpenAs",
            ],
            capture_output=True,
            text=True,
            timeout=15,
            creationflags=flags,
        )
        if r.returncode == 0:
            return True
    except Exception:
        pass

    try:
        import win32com.client  # type: ignore

        folder = win32com.client.Dispatch("Shell.Application").Namespace(
            os.path.dirname(abs_path)
        )
        item = folder.ParseName(os.path.basename(abs_path))
        if item is None:
            return False
        open_with_tokens = (
            "openas",
            "open with",
            "openwith",
            "開啟方式",
            "選擇開啟方式",
            "打开方式",
            "选择打开方式",
        )
        for verb_key in open_with_tokens:
            try:
                item.InvokeVerb(verb_key)
                return True
            except Exception:
                continue
        for verb in item.Verbs():
            try:
                name = str(getattr(verb, "Name", "") or "").replace("&", "").strip().lower()
                if any(token in name for token in open_with_tokens):
                    verb.DoIt()
                    return True
            except Exception:
                continue
    except Exception:
        return False
    return False


def _share_windows_clipboard_cf_hdrop(path: str) -> bool:
    """Place file(s) on clipboard as CF_HDROP (native Windows file clipboard)."""
    import struct

    try:
        import win32clipboard  # type: ignore
        import win32con  # type: ignore
    except ImportError:
        return False

    abs_path = os.path.abspath(path)
    if not os.path.isfile(abs_path):
        return False
    paths = (abs_path + "\0").encode("utf-16le") + b"\x00\x00"
    dropfiles = struct.pack("<IIIII", 20, 0, 0, 0, 1)
    data = dropfiles + paths
    try:
        win32clipboard.OpenClipboard()
        try:
            win32clipboard.EmptyClipboard()
            win32clipboard.SetClipboardData(win32con.CF_HDROP, data)
        finally:
            win32clipboard.CloseClipboard()
        return True
    except Exception:
        try:
            win32clipboard.CloseClipboard()
        except Exception:
            pass
        return False


def _share_windows_clipboard_cf_hdrop_paths(file_paths: List[str]) -> bool:
    """Place multiple files on the clipboard as CF_HDROP."""
    import struct

    try:
        import win32clipboard  # type: ignore
        import win32con  # type: ignore
    except ImportError:
        return False

    abs_paths = [
        os.path.abspath(p) for p in file_paths if p and os.path.isfile(os.path.abspath(p))
    ]
    if not abs_paths:
        return False
    if len(abs_paths) == 1:
        return _share_windows_clipboard_cf_hdrop(abs_paths[0])
    paths_blob = "".join(p + "\0" for p in abs_paths).encode("utf-16le") + b"\x00\x00"
    dropfiles = struct.pack("<IIIII", 20, 0, 0, 0, len(abs_paths))
    data = dropfiles + paths_blob
    try:
        win32clipboard.OpenClipboard()
        try:
            win32clipboard.EmptyClipboard()
            win32clipboard.SetClipboardData(win32con.CF_HDROP, data)
        finally:
            win32clipboard.CloseClipboard()
        return True
    except Exception:
        try:
            win32clipboard.CloseClipboard()
        except Exception:
            pass
        return False


def _share_windows_clipboard_file_via_powershell(path: str) -> bool:
    """Put the file object on the clipboard (Windows) so the user can paste into Mail, Teams, Explorer, etc."""
    import subprocess

    abs_path = os.path.abspath(path)
    if not os.path.isfile(abs_path):
        return False
    flags = 0
    if sys.platform == "win32" and hasattr(subprocess, "CREATE_NO_WINDOW"):
        flags = subprocess.CREATE_NO_WINDOW  # type: ignore[attr-defined]
    try:
        r = subprocess.run(
            [
                "powershell",
                "-NoProfile",
                "-Sta",
                "-Command",
                "Set-Clipboard",
                "-LiteralPath",
                abs_path,
            ],
            capture_output=True,
            text=True,
            timeout=20,
            creationflags=flags,
        )
        return r.returncode == 0
    except Exception:
        return False


def _resolve_windows_share_helper_exe():
    """Locate built WindowsShareHelper.exe (dev tree or bundled install)."""
    rel = os.path.join(
        "windows_share_helper",
        "bin",
        "Release",
        "net8.0-windows10.0.19041.0",
        "WindowsShareHelper.exe",
    )
    here = os.path.dirname(os.path.abspath(__file__))
    candidates = [os.path.join(here, rel)]
    if getattr(sys, "frozen", False):
        exe_dir = os.path.dirname(os.path.abspath(sys.executable))
        candidates.append(os.path.join(exe_dir, "WindowsShareHelper.exe"))
        meipass = getattr(sys, "_MEIPASS", None)
        if meipass:
            candidates.append(os.path.join(meipass, "WindowsShareHelper.exe"))
    for candidate in candidates:
        if candidate and os.path.isfile(candidate):
            return candidate
    return None


def _share_windows_via_helper(path: str, owner_hwnd: int) -> bool:
    """Launch the .NET helper that wraps IDataTransferManagerInterop."""
    import subprocess
    import time

    helper = _resolve_windows_share_helper_exe()
    if not helper:
        return False
    abs_path = os.path.abspath(path)
    if not os.path.isfile(abs_path):
        return False
    flags = 0
    if hasattr(subprocess, "CREATE_NO_WINDOW"):
        flags = subprocess.CREATE_NO_WINDOW  # type: ignore[attr-defined]
    try:
        proc = subprocess.Popen(
            [helper, str(int(owner_hwnd or 0)), abs_path],
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            creationflags=flags,
        )
        # Fail fast if the helper exits immediately, but never block the Qt UI
        # thread for hundreds of ms — that prevented the share flyout on first click.
        app = None
        try:
            from PyQt6.QtWidgets import QApplication

            app = QApplication.instance()
        except Exception:
            app = None
        deadline = time.time() + 0.15
        while time.time() < deadline:
            rc = proc.poll()
            if rc is not None:
                return rc == 0
            if app is not None:
                app.processEvents()
            time.sleep(0.01)
        return True
    except Exception:
        return False


def _share_windows_via_winrt(path: str, owner_hwnd: int) -> bool:
    """In-process WinRT share sheet (DataTransferManager + interop)."""
    if not owner_hwnd:
        return False
    try:
        from windows_share import share_file_windows

        return bool(share_file_windows(path, owner_hwnd))
    except Exception:
        return False



