    def is_animated_image(self, file_path: str) -> bool:
        if not file_path:
            return False
        ext = os.path.splitext(file_path)[1].lower()
        if ext == '.gif':
            return True
        if ext == '.webp':
            try:
                from PIL import Image
                with Image.open(file_path) as img:
                    return getattr(img, "is_animated", False) and int(getattr(img, "n_frames", 1)) > 1
            except Exception:
                return False
        return False

    def _stop_animations(self):
        if hasattr(self, "_current_movie") and self._current_movie:
            try:
                self._current_movie.stop()
            except Exception:
                pass
            self.image_label.setMovie(None)
            self._current_movie = None
            
        if hasattr(self, "_webp_timer") and self._webp_timer:
            try:
                self._webp_timer.stop()
            except Exception:
                pass
            self._webp_timer = None
            
        self._current_webp_frames = []
        self._current_webp_durations = []
        self._current_webp_idx = 0
        self._webp_decode_generation = getattr(self, "_webp_decode_generation", 0) + 1
        self._webp_decode_in_progress_path = None
        self._original_movie_size = None

    def _animated_playback_active(self, file_path: str | None = None) -> bool:
        """True when GIF/WebP animation is loaded or decoding for this path."""
        path = file_path or getattr(self, "current_file_path", None)
        if not path or not self.is_animated_image(path):
            return False
        if _norm_path(path) != _norm_path(getattr(self, "current_file_path", None) or ""):
            return False
        if getattr(self, "_current_movie", None) is not None:
            return True
        if getattr(self, "_current_webp_frames", None):
            return len(self._current_webp_frames) > 0
        pending = getattr(self, "_webp_decode_in_progress_path", None)
        return bool(pending and _norm_path(pending) == _norm_path(path))

    def _mark_animated_content_displayed(self, file_path: str) -> None:
        self._displayed_content_path = file_path
        self._on_single_view_content_displayed()

    def _load_and_start_animation(self, file_path):
        self._stop_animations()
        # Animated GIF/WebP always play fit-to-window; no 100% zoom or pan.
        self.fit_to_window = True
        self.current_zoom_level = 1.0
        self.zoom_center_point = None
        self._pending_zoom = False
        self._pending_zoom_center = None
        self._pending_zoom_thumbnail_size = None
        self._pending_zoom_toggle = False
        
        # Hide GPU view, show scroll area/image label (animated formats only)
        container = getattr(self, "single_view_container", None)
        if container is not None and hasattr(container, "set_gpu_view_active"):
            container.set_gpu_view_active(False)
        elif getattr(self, "gpu_view", None) is not None:
            self.gpu_view.hide()
            self.scroll_area.show()
        self.image_label.show()
        self.image_label.setText("")
        
        # Hide loading overlay if visible
        if hasattr(self, "loading_overlay") and self.loading_overlay:
            self.loading_overlay.hide_loading()
            
        ext = os.path.splitext(file_path)[1].lower()
        if ext == '.gif':
            from PyQt6.QtGui import QMovie
            self._current_movie = QMovie(file_path)
            self.image_label.setMovie(self._current_movie)
            
            def on_frame_changed(frame_no):
                if not self._current_movie:
                    return
                try:
                    self._current_movie.frameChanged.disconnect(on_frame_changed)
                except Exception:
                    pass
                movie_size = self._current_movie.frameRect().size()
                self._original_movie_size = movie_size
                self._update_gif_scaling()
                
            self._current_movie.frameChanged.connect(on_frame_changed)
            self._current_movie.start()
            self._mark_animated_content_displayed(file_path)
            self.status_bar.showMessage(f"Playing GIF: {os.path.basename(file_path)}")
            return True
        elif ext == '.webp':
            token = getattr(self, "_webp_decode_generation", 0) + 1
            self._webp_decode_generation = token
            self._webp_decode_in_progress_path = file_path
            self._current_webp_frames = []
            self._current_webp_durations = []
            self._current_webp_idx = 0

            signals = getattr(self, "_webp_decode_signals", None)
            if signals is None:
                signals = WebpDecodeSignals()
                signals.ready.connect(self._on_webp_frames_decoded)
                signals.failed.connect(self._on_webp_decode_failed)
                self._webp_decode_signals = signals

            self.status_bar.showMessage(
                f"Decoding WebP: {os.path.basename(file_path)}"
            )

            class _WebpDecodeWorker(QRunnable):
                def run(self_inner):
                    try:
                        from PIL import Image

                        frames = []
                        durations = []
                        with Image.open(file_path) as img:
                            n_frames = getattr(img, "n_frames", 1)
                            if n_frames <= 1:
                                raise ValueError("WebP is not animated")
                            for frame_idx in range(n_frames):
                                img.seek(frame_idx)
                                frame_rgba = img.convert("RGBA")
                                w, h = frame_rgba.size
                                data = frame_rgba.tobytes("raw", "RGBA")
                                qim = QImage(
                                    data, w, h, QImage.Format.Format_RGBA8888
                                ).copy()
                                frames.append(qim)
                                duration = img.info.get("duration", 100)
                                if duration <= 0:
                                    duration = 100
                                durations.append(duration)
                    except Exception as e:
                        try:
                            from PyQt6 import sip

                            if not sip.isdeleted(signals):
                                signals.failed.emit(file_path, str(e))
                        except Exception:
                            pass
                        return

                    try:
                        from PyQt6 import sip

                        if not sip.isdeleted(signals):
                            signals.ready.emit(token, file_path, frames, durations)
                    except Exception:
                        pass

            _get_bg_thread_pool().start(_WebpDecodeWorker())
            return True
        return False

    def _on_webp_frames_decoded(
        self, token: int, file_path: str, qimages: list, durations: list
    ) -> None:
        if token != getattr(self, "_webp_decode_generation", None):
            return
        if _norm_path(file_path) != _norm_path(getattr(self, "current_file_path", None)):
            return
        if not qimages:
            return

        self._webp_decode_in_progress_path = None
        self._current_webp_frames = [QPixmap.fromImage(qim) for qim in qimages]
        self._current_webp_durations = list(durations)
        self._current_webp_idx = 0
        self._webp_timer = QTimer(self)
        self._webp_timer.setSingleShot(True)
        self._webp_timer.timeout.connect(self._play_next_webp_frame)
        self._play_next_webp_frame()
        self._mark_animated_content_displayed(file_path)
        self.status_bar.showMessage(f"Playing WebP: {os.path.basename(file_path)}")

    def _on_webp_decode_failed(self, file_path: str, error_message: str) -> None:
        if _norm_path(file_path) != _norm_path(getattr(self, "current_file_path", None)):
            return
        self._webp_decode_in_progress_path = None
        import logging

        logging.getLogger(__name__).error(
            "Error loading animated WebP: %s", error_message, exc_info=True
        )
        self.image_label.setText(f"Error loading WebP: {error_message}")

    def _play_next_webp_frame(self):
        if not hasattr(self, "_current_webp_frames") or not self._current_webp_frames:
            return
        idx = self._current_webp_idx
        pixmap = self._current_webp_frames[idx]
        
        display_pixmap = pixmap
        if self.fit_to_window:
            v_size = self.scroll_area.viewport().size()
            display_pixmap = pixmap.scaled(v_size, Qt.AspectRatioMode.KeepAspectRatio, Qt.TransformationMode.SmoothTransformation)
        
        self.image_label.setPixmap(display_pixmap)
        self.image_label.resize(display_pixmap.size())
        
        duration = self._current_webp_durations[idx]
        self._current_webp_idx = (idx + 1) % len(self._current_webp_frames)
        
        if hasattr(self, "_webp_timer") and self._webp_timer:
            self._webp_timer.start(duration)

    def _update_webp_scaling(self):
        if hasattr(self, "_current_webp_frames") and self._current_webp_frames:
            idx = (self._current_webp_idx - 1) % len(self._current_webp_frames)
            pixmap = self._current_webp_frames[idx]
            display_pixmap = pixmap
            if self.fit_to_window:
                v_size = self.scroll_area.viewport().size()
                display_pixmap = pixmap.scaled(v_size, Qt.AspectRatioMode.KeepAspectRatio, Qt.TransformationMode.SmoothTransformation)
            self.image_label.setPixmap(display_pixmap)
            self.image_label.resize(display_pixmap.size())

    def _update_gif_scaling(self):
        if not hasattr(self, "_current_movie") or not self._current_movie:
            return
        orig_size = getattr(self, "_original_movie_size", None)
        if not orig_size or orig_size.isEmpty():
            return
        if self.fit_to_window:
            v_size = self.scroll_area.viewport().size()
            w_ratio = v_size.width() / orig_size.width()
            h_ratio = v_size.height() / orig_size.height()
            ratio = min(w_ratio, h_ratio)
            fitted_size = QSize(int(orig_size.width() * ratio), int(orig_size.height() * ratio))
            self._current_movie.setScaledSize(fitted_size)
            self.image_label.resize(fitted_size)
        else:
            self._current_movie.setScaledSize(orig_size)
            self.image_label.resize(orig_size)


    def _on_view_mode_button_clicked(self) -> None:
        if getattr(self, "view_mode", "") == "compare":
            self._exit_compare_mode()
            return
        if getattr(self, "_burst_group_view_active", False):
            if getattr(self, "view_mode", "") == "single":
                if not self._path_in_burst_group_view(getattr(self, "current_file_path", None)):
                    self._exit_burst_group_view()
                self.view_mode = "gallery"
                self._show_gallery_view()
                return
            self._exit_burst_group_view()
            return
        self.toggle_view_mode()

    # GALLERY FUNCTIONALITY COMMENTED OUT
    def toggle_view_mode(self):
        """Toggle between single image view and gallery view"""
        if getattr(self, '_is_delete_dialog_open', False):
            return
        # Do not block gallery entry on EXIF sort. Large cold folders can take
        # minutes to probe; _apply_folder_sort_refinement still reorders later.
        if not self._is_exif_sort_ready():
            import logging
            logging.getLogger(__name__).info(
                "[VIEW_MODE] EXIF sort still running; entering gallery on provisional order"
            )
        if getattr(self, "view_mode", "") == "compare":
            self._exit_compare_mode()
            return
        self._last_view_mode_switch_ts = time.monotonic()
        import logging
        logger = logging.getLogger(__name__)
        logger.debug("[MODESWITCH] toggle_view_mode called; current=%s", self.view_mode)
        logger.info("[VIEW_MODE] ========== toggle_view_mode() STARTED ==========")
        
        if self.view_mode == 'single':
            logger.info("[VIEW_MODE] Switching from single to gallery mode")
            self._disable_raw_recovery()
            self._gallery_entry_accept_embedded = False
            self.view_mode = 'gallery'
            try:
                if hasattr(self, "_resume_indexing_timer") and self._resume_indexing_timer:
                    self._resume_indexing_timer.stop()
                self._pause_semantic_indexing_deferred()
            except Exception:
                pass
            if getattr(self, "_focus_subject_outline_active", False):
                self._focus_subject_outline_active = False
                self._focus_subject_rect_image = None
                self._focus_rect_source = None
        else:
            logger.info("[VIEW_MODE] Switching from gallery to single mode")
            self.view_mode = 'single'
            self._adopt_gallery_navigation_path()
            self._loading_from_gallery = True
            self._gallery_entry_accept_embedded = True
        
        logger.info("[VIEW_MODE] Mode changed, calling view method (elapsed: 0.000s)")
        if self.view_mode == 'gallery':
            self._stop_slideshow()
            self._show_gallery_view()
        else:
            self._show_single_view()
        logger.debug("[MODESWITCH] toggle_view_mode finished; current=%s", self.view_mode)
        
        logger.info("[VIEW_MODE] ========== toggle_view_mode() COMPLETED in 0.004s ==========")
    
    def _resume_indexing_if_single_view(self):
        """Resume background indexing only if the user has settled in single view mode."""
        if getattr(self, "view_mode", "single") != "single":
            return
        if getattr(self, "_folder_fast_open_token", None) is not None:
            if hasattr(self, "_resume_indexing_timer") and self._resume_indexing_timer:
                self._resume_indexing_timer.start(3000)
            return
        if not getattr(self, "_single_view_first_render_logged", False):
            if hasattr(self, "_resume_indexing_timer") and self._resume_indexing_timer:
                self._resume_indexing_timer.start(3000)
            return
        try:
            self._get_semantic_index().pause_indexing(False)
            import logging

            logging.getLogger(__name__).info(
                "[VIEW_MODE] Background indexing resumed after idle period in single view"
            )
        except Exception:
            pass

    def _resume_indexing_if_gallery_idle(self):
        """Gallery browsing keeps background indexing paused; resume only when idle/settled."""
        if getattr(self, "view_mode", "") != "gallery":
            return
        import logging
        logger = logging.getLogger(__name__)

        # Check if there are active high-priority (CURRENT) tasks in the image manager
        if hasattr(self, "image_manager") and self.image_manager is not None:
            try:
                from image_load_manager import Priority
                with self.image_manager._queue_lock:
                    for task in self.image_manager._active_tasks.values():
                        if (
                            getattr(task, "priority", None) == Priority.CURRENT
                            and not task.is_cancelled()
                        ):
                            logger.debug(
                                "[VIEW_MODE] Deferring background indexing: high-priority gallery task active"
                            )
                            if hasattr(self, "_resume_indexing_timer") and self._resume_indexing_timer:
                                self._resume_indexing_timer.start(3000)
                            return
            except Exception as e:
                logger.error(f"Error checking active image manager tasks: {e}")

        try:
            self._get_semantic_index().pause_indexing(False)
            logger.info(
                "[VIEW_MODE] Background indexing resumed after idle period in gallery view"
            )
        except Exception as e:
            logger.error(f"Error resuming background indexing in gallery view: {e}")

    def _show_single_view(self):
        """Show single image view"""
        import logging
        import time
        import os
        logger = logging.getLogger(__name__)
        if getattr(self, "view_mode", "single") == "gallery":
            logger.debug("[VIEW_MODE] _show_single_view skipped; view_mode is gallery")
            return
        start_time = time.time()
        logger.info(f"[VIEW_MODE] ========== _show_single_view() STARTED at {start_time} ==========")
        if hasattr(self.image_manager, "set_gallery_view_active"):
            self.image_manager.set_gallery_view_active(False)
        self._suppress_single_manager_callbacks = False
        # Gallery entry aborts/defers CuPy import; resume once back in single view.
        try:
            self._schedule_deferred_gpu_backend_import(reason="fallback")
        except Exception:
            pass
        try:
            from PyQt6.QtCore import QTimer
            self._pause_semantic_indexing_deferred()
            if hasattr(self, "_resume_indexing_timer") and self._resume_indexing_timer:
                self._resume_indexing_timer.stop()
            
            self._resume_indexing_timer = QTimer(self)
            self._resume_indexing_timer.setSingleShot(True)
            self._resume_indexing_timer.timeout.connect(self._resume_indexing_if_single_view)
            self._resume_indexing_timer.start(5000)
        except Exception:
            pass
        
        self._end_gallery_indexing_deferral()
        if hasattr(self, "_idle_display_prefetch_timer") and self._idle_display_prefetch_timer:
            self._idle_display_prefetch_timer.stop()
        self._pause_prefetch_for_navigation()
        # Stop all gallery background loading when switching to single view
        if hasattr(self, 'gallery_justified') and self.gallery_justified:
            gj = self.gallery_justified
            gj._background_loading_active = False
            if hasattr(gj, "_stop_layout_rebuild_timers"):
                gj._stop_layout_rebuild_timers()
            if hasattr(gj, "cancel_background_loading"):
                gj.cancel_background_loading()
            elif hasattr(gj, "suspend_thumbnail_display"):
                gj.suspend_thumbnail_display()
            # Cancel any pending background loads
            if hasattr(self.gallery_justified, '_load_queue'):
                self.gallery_justified._load_queue.clear()
            # Drop queued gallery thumbnail decodes (all CURRENT priority) so the
            # image being opened is not stuck behind dozens of them in the worker
            # pool. Protect the foreground file, whose decode may already be in
            # flight (fast-open) or about to be requested in Step 4.
            try:
                mgr = getattr(self, "image_manager", None)
                if mgr is not None:
                    if hasattr(mgr, "cancel_gallery_tasks"):
                        mgr.cancel_gallery_tasks()
                    elif hasattr(mgr, "cancel_all_tasks_except"):
                        mgr.cancel_all_tasks_except(getattr(self, "current_file_path", None))
                if hasattr(self.gallery_justified, "_active_tasks"):
                    keep = getattr(self, "current_file_path", None)
                    for p in list(self.gallery_justified._active_tasks.keys()):
                        if p != keep:
                            self.gallery_justified._active_tasks.pop(p, None)
            except Exception:
                pass
            logger.debug("[VIEW_MODE] Stopped all gallery background loading")
        
        if hasattr(self, "loading_overlay"):
            self.loading_overlay.hide_loading()
        
        # Step 1: Hide gallery widget
        hide_start = time.time()
        if hasattr(self, 'gallery_widget') and self.gallery_widget:
            self.gallery_widget.hide()
            self._position_gallery_frame_grip()
        if hasattr(self, "compare_widget") and self.compare_widget:
            self.compare_widget.hide()
        hide_time = time.time() - hide_start
        logger.info(f"[VIEW_MODE] Step 1: Gallery widget hidden (elapsed: {hide_time:.3f}s)")
        
        # Step 2: Show single-image area (scroll + histogram)
        show_start = time.time()
        if hasattr(self, 'single_view_container') and self.single_view_container:
            self.single_view_container.show()
            if hasattr(self.single_view_container, "_layout_filmstrip"):
                self.single_view_container._layout_filmstrip()
            self._sync_gpu_single_view_visibility()
        else:
            self.scroll_area.show()
        show_time = time.time() - show_start
        logger.info(f"[VIEW_MODE] Step 2: Single view container shown (elapsed: {show_time:.3f}s)")
        
        # Step 3: Show UI elements
        ui_start = time.time()
        # Show status bar footer (metadata and image counter)
        if hasattr(self, 'status_bar'):
            self.status_bar.show()
        if hasattr(self, 'status_counter_label'):
            self._refresh_image_counter()
        
        # In single view mode: hide sort button and size slider, show Gallery button only if EXIF sort is ready
        if hasattr(self, 'sort_toggle_button'):
            self.sort_toggle_button.hide()
        if hasattr(self, 'size_slider'):
            self.size_slider.hide()

        if hasattr(self, 'view_mode_button'):
            self.view_mode_button.setVisible(self._is_exif_sort_ready())
        if hasattr(self, "search_bottom_button"):
            self.search_bottom_button.setVisible(bool(self.image_files) and self._is_exif_sort_ready())
        # Update icon if using qtawesome
        if qta is not None:
            try:
                gallery_icon = _qta_icon('fa5s.th', color=theme.INK_MUTED)
                self.view_mode_button.setIcon(gallery_icon)
                self.view_mode_button.setIconSize(QSize(20, 20))
                self.view_mode_button.setText("")  # Clear text if using icon
            except Exception:
                self.view_mode_button.setText("Gallery")
        else:
            self.view_mode_button.setText("Gallery")
        self._schedule_search_expand_overlay_sync()
        self._sync_compare_button_visibility()
        
        ui_time = time.time() - ui_start
        logger.info(f"[VIEW_MODE] Step 3: UI elements shown (elapsed: {ui_time:.3f}s)")
        
        # Step 4: Reload current image if available
        if self.current_file_path:
            load_start = time.time()
            path = self.current_file_path
            logger.info(f"[VIEW_MODE] Step 4: Starting image reload: {os.path.basename(path)}")

            last_path = getattr(self, "_last_loaded_path", None)
            displayed_path = getattr(self, "_displayed_content_path", None)
            from_gallery = getattr(self, "_loading_from_gallery", False)
            path_changed = (
                _norm_path(path) != _norm_path(last_path or "")
                or _norm_path(path) != _norm_path(displayed_path or "")
            )

            gallery_instant = False
            if path_changed or from_gallery:
                if self._animated_playback_active(path):
                    logger.info(
                        "[VIEW_MODE] Keeping active GIF/WebP playback for %s",
                        os.path.basename(path),
                    )
                elif self._paint_instant_preview_for_path(path, prefer_gallery=from_gallery):
                    gallery_instant = getattr(self, "_gallery_instant_display_quality", False)
                elif path_changed:
                    self._clear_stale_single_view_image()
                if not from_gallery and hasattr(self, "loading_overlay"):
                    if not gallery_instant:
                        self.loading_overlay.show_loading("Loading Image...")

            if (
                from_gallery
                and gallery_instant
                and _norm_path(getattr(self, "_displayed_content_path", "")) == _norm_path(path)
                and self._single_view_pixels_on_screen(path)
            ):
                logger.info(
                    "[VIEW_MODE] Gallery→single: display-quality preview already painted, "
                    "skipping load_raw_image"
                )
                self._finish_gallery_to_single_without_redisplay(path)
                self.update_status_bar()
            else:
                is_already_loaded = (
                    not path_changed
                    and not from_gallery
                    and _norm_path(last_path or "") == _norm_path(path)
                    and (
                        (
                            getattr(self, "_base_display_pixmap", None) is not None
                            and not self._base_display_pixmap.isNull()
                        )
                        or (
                            getattr(self, "current_pixmap", None) is not None
                            and not self.current_pixmap.isNull()
                        )
                    )
                )

                if is_already_loaded:
                    logger.info("[VIEW_MODE] Image already in memory, skipping reload")
                    base = getattr(self, "_base_display_pixmap", None)
                    if base is not None and not base.isNull():
                        self.display_pixmap(base)
                    elif (
                        getattr(self, "current_pixmap", None) is not None
                        and not self.current_pixmap.isNull()
                        and not self._get_visual_rotation_degrees(self.current_file_path)
                    ):
                        self.display_pixmap(self.current_pixmap)
                    else:
                        self.load_raw_image(self.current_file_path)
                    if hasattr(self, "loading_overlay"):
                        self.loading_overlay.hide_loading()
                    logger.info(
                        "[VIEW_MODE] Updating status bar to ensure metadata is displayed"
                    )
                    self.update_status_bar()
                else:
                    cached_pixmap = None
                    if not from_gallery and not path_changed:
                        try:
                            if hasattr(self, "image_cache"):
                                cached_pixmap = self.image_cache.get_pixmap(path)
                                if cached_pixmap and not cached_pixmap.isNull():
                                    logger.info(
                                        "[VIEW_MODE] Using cached pixmap from image cache "
                                        "for instant display"
                                    )
                                    # Cached pixmaps already have orientation applied, do not re-apply
                                    self._orientation_already_applied = True
                                    self.display_pixmap(cached_pixmap)
                                    if hasattr(self, "loading_overlay"):
                                        self.loading_overlay.hide_loading()
                        except Exception as e:
                            logger.debug(f"[VIEW_MODE] Error using cached pixmap: {e}")

                    if getattr(self, "_skip_next_single_view_load", False):
                        self._skip_next_single_view_load = False
                        logger.info(
                            "[VIEW_MODE] Skipping load_raw_image for %s "
                            "(fast-open decode already started)",
                            os.path.basename(path),
                        )
                    elif (
                        not from_gallery
                        and _norm_path(path)
                        == _norm_path(
                            getattr(self, "_single_view_load_request_path", "") or ""
                        )
                        and getattr(self, "_single_view_first_render_logged", False)
                        and self._single_view_pixels_on_screen(path)
                    ):
                        logger.info(
                            "[VIEW_MODE] Skipping load_raw_image for %s "
                            "(first-render already on screen)",
                            os.path.basename(path),
                        )
                        if hasattr(self, "loading_overlay"):
                            self.loading_overlay.hide_loading()
                        self.update_status_bar()
                    else:
                        logger.info(
                            f"[VIEW_MODE] Triggering load_raw_image for {os.path.basename(path)}"
                        )
                        self.load_raw_image(path)
            load_time = time.time() - load_start
            logger.info(f"[VIEW_MODE] Step 4: Image reload completed (elapsed: {load_time:.3f}s)")
        else:
            # Update status bar to show metadata even if no image is loaded
            self.update_status_bar()
            logger.info("[VIEW_MODE] Step 4: No image to reload, status bar updated")

        self._sync_single_image_histogram()
        self._sync_filmstrip_to_folder()
        
        total_time = time.time() - start_time
        logger.info("[VIEW_MODE] ========== TIMING BREAKDOWN ==========")
        # GALLERY FUNCTIONALITY COMMENTED OUT
        # if self.gallery_widget:
        #     logger.info(f"[VIEW_MODE] Hide gallery widget: {hide_time:.3f}s")
        logger.info(f"[VIEW_MODE] Show scroll area: {show_time:.3f}s")
        logger.info(f"[VIEW_MODE] Show UI elements: {ui_time:.3f}s")
        if self.current_file_path:
            logger.info(f"[VIEW_MODE] Image reload: {load_time:.3f}s")
        self.setFocus()
        QTimer.singleShot(0, self._restore_keyboard_focus)
        logger.info(f"[VIEW_MODE] ========== SINGLE VIEW RENDERING COMPLETED in {total_time:.3f}s ==========")
    
    # GALLERY FUNCTIONALITY COMMENTED OUT
    def _cancel_filmstrip_prefetch_for_gallery(self) -> None:
        """Stop filmstrip/neighbor prefetch before gallery thumbnail loads."""
        self._filmstrip_prefetch_pending = []
        self._filmstrip_prefetch_draining = False
        if hasattr(self, "_deferred_filmstrip_paths") and self._deferred_filmstrip_paths:
            self._deferred_filmstrip_paths.clear()
        self._pause_prefetch_for_navigation()

    def _release_single_view_heavy_buffers_for_gallery(self) -> None:
        """Free GPU/RAM held by the open single-view full-res decode before gallery tiles load."""
        import logging
        import sys

        from PyQt6.QtGui import QPixmap

        logger = logging.getLogger(__name__)
        cur = getattr(self, "current_file_path", None)

        self._cancel_content_crossfade()
        self._full_resolution_loading = False

        gv = getattr(self, "gpu_view", None)
        gl_cleared = False
        gl_deferred = False
        gl_pending = False
        if gv is not None:
            try:
                if hasattr(gv, "release_for_gallery_entry"):
                    hidden = (
                        hasattr(gv, "_viewport_hidden_for_teardown")
                        and gv._viewport_hidden_for_teardown()
                    )
                    had_heavy = (
                        hasattr(gv, "has_heavy_pixmap") and gv.has_heavy_pixmap()
                    )
                    gv.release_for_gallery_entry()
                    if sys.platform == "win32" and gv.is_opengl_viewport():
                        if hidden and not had_heavy:
                            gl_cleared = True
                        elif hidden and had_heavy:
                            gl_cleared = not gv.has_heavy_pixmap()
                            gl_pending = gv.has_heavy_pixmap()
                        else:
                            gl_deferred = True
                            gl_pending = had_heavy
                    else:
                        gl_cleared = True
                else:
                    gv.clear()
                    gl_cleared = True
            except Exception:
                pass

        label = getattr(self, "image_label", None)
        if label is not None:
            try:
                label.setPixmap(QPixmap())
            except Exception:
                pass
        self.current_pixmap = None
        self._manager_displayed_max_dim = 0
        self._gpu_last_path = None

        cache = getattr(self, "image_cache", None)
        if cur and cache is not None and hasattr(cache, "release_full_image_memory"):
            try:
                cache.release_full_image_memory(cur)
            except Exception:
                pass

        logger.info(
            "[GALLERY] Released single-view full-res buffers for gallery entry (%s, gl_cleared=%s gl_deferred=%s gl_pending=%s)",
            os.path.basename(cur) if cur else "none",
            gl_cleared,
            gl_deferred,
            gl_pending,
        )

    def _show_gallery_view(self):
        """Show gallery view - based on reference code"""
        self._gallery_entry_accept_embedded = False
        self._stop_animations()
        import logging
        import os
        import sys
        import time
        from PyQt6.QtCore import QTimer
        logger = logging.getLogger(__name__)
        self._suppress_single_manager_callbacks = True
        try:
            # Session restore may still be staging full decode / CuPy import;
            # abort that before raising gallery concurrency or tiles starve.
            self._abort_session_restore_heavy_for_gallery()
            self._defer_background_indexing_for_gallery()
            if hasattr(self, "image_manager") and self.image_manager is not None:
                mgr = self.image_manager
                if hasattr(mgr, "enter_gallery_warmup_throttle"):
                    mgr.enter_gallery_warmup_throttle()
            if hasattr(self, "_resume_indexing_timer") and self._resume_indexing_timer:
                self._resume_indexing_timer.stop()
            self._resume_indexing_timer = QTimer(self)
            self._resume_indexing_timer.setSingleShot(True)
            self._resume_indexing_timer.timeout.connect(self._resume_indexing_if_gallery_idle)
            file_count = len(getattr(self, "image_files", []) or [])
            resume_ms = min(30000, max(8000, 8000 + (file_count // 500) * 2000))
            self._resume_indexing_timer.start(resume_ms)
        except Exception:
            pass
        bar = self._filmstrip_bar()
        if bar is not None:
            bar.hide()
            bar.setEnabled(False)
        self._hide_filmstrip_chrome()
        logger.debug("[MODESWITCH] _show_gallery_view entered; files=%d", len(self.image_files))
        logger.info("[GALLERY] Showing gallery view")
        if hasattr(self.image_manager, "set_gallery_view_active"):
            self.image_manager.set_gallery_view_active(True)
        if getattr(self, "current_file_path", None):
            self._gallery_scroll_target_path = self.current_file_path
        # Only queue entry-scroll when the gallery still needs a fresh layout.
        # Re-entry with an intact layout must not set _pending_scroll_to_path
        # (that parked load_visible and left tiles blank for seconds).
        if getattr(self, "gallery_justified", None) is not None:
            gj = self.gallery_justified
            display_files = self._gallery_files_for_display()
            already_laid_out = bool(
                display_files
                and hasattr(gj, "_layout_matches_current_images")
                and gj._layout_matches_current_images(display_files)
                and getattr(gj, "_gallery_layout_items", None)
            )
            if not already_laid_out:
                self._scroll_gallery_to_current_file(backup=False)
        self._stop_slideshow()
        if hasattr(self, "loading_overlay"):
            self.loading_overlay.hide_loading()
        if hasattr(self, "_idle_display_prefetch_timer") and self._idle_display_prefetch_timer:
            self._idle_display_prefetch_timer.stop()

        self._cancel_filmstrip_prefetch_for_gallery()
        if hasattr(self, "_idle_display_prefetch_timer") and self._idle_display_prefetch_timer:
            self._idle_display_prefetch_timer.stop()

        # Entering gallery: drop leftover single-view decode/preload work so scrolling
        # thumbnails doesn't compete with stale full-image tasks.
        try:
            if hasattr(self, "image_manager") and self.image_manager is not None:
                mgr = self.image_manager
                if hasattr(mgr, "cancel_non_gallery_tasks"):
                    mgr.cancel_non_gallery_tasks()
                if hasattr(mgr, "cancel_queued_non_gallery_tasks"):
                    mgr.cancel_queued_non_gallery_tasks()
                if hasattr(mgr, "cancel_tasks_by_priority"):
                    from image_load_manager import Priority as _GalleryCancelPriority

                    for prio in (
                        _GalleryCancelPriority.PRELOAD_NEXT,
                        _GalleryCancelPriority.PRELOAD_PREV,
                        _GalleryCancelPriority.BACKGROUND,
                    ):
                        mgr.cancel_tasks_by_priority(prio)
                elif hasattr(mgr, "flush_queue"):
                    mgr.flush_queue()
                else:
                    mgr.cancel_all_tasks()
            if hasattr(self, "preload_manager") and self.preload_manager is not None:
                self.preload_manager.cancel_all_preloads()
        except Exception:
            pass

        # Track gallery loading start time for performance monitoring
        if hasattr(self, 'gallery_justified') and self.gallery_justified:
            gj = self.gallery_justified
            gj._is_scrolling_fast = False
            gj._current_scroll_speed = 0.0
            gj._first_thumb_ready_after_set = False
            if hasattr(gj, "_active_tasks"):
                gj._active_tasks.clear()
            if hasattr(gj, "_requested_thumbnail_paths"):
                gj._requested_thumbnail_paths.clear()
            if hasattr(gj, "_stop_layout_rebuild_timers"):
                gj._stop_layout_rebuild_timers()
            gj._gallery_load_start_time = time.time()
            gj._visible_images_to_load = 0
            gj._visible_images_loaded = 0
            logger.info(f"[GALLERY] Gallery load timing started at {gj._gallery_load_start_time:.3f}")
        
        # Update title / top metadata for gallery mode
        if hasattr(self, 'current_folder') and self.current_folder:
            folder_name = os.path.basename(self.current_folder)
            title = f"RAWviewer - {folder_name}"
        else:
            title = "RAWviewer"
        if platform.system() == "Darwin":
            self._apply_top_metadata_text(
                os.path.basename(str(self.current_folder or ""))
            )
        else:
            self.setWindowTitle(title)
            if hasattr(self, 'title_bar') and self.title_bar is not None:
                self.title_bar.set_title(title)
        
        # Create gallery widget if needed (at most one container in the layout)
        if not self._ensure_gallery_widget():
            return
        # Warmup caps (active_cap=12–18 for 1k+ folders) only apply after the widget
        # exists; calling begin_gallery_warmup earlier is a no-op on first gallery entry.
        self._arm_gallery_warmup()
        
        # Close the editor before leaving single view: _show_gallery_view only
        # ever hid single_view_container, never the Adjust panel itself, so a
        # still-open editor stayed visible over the gallery (splitter gives it
        # the space single_view_container gave up) and left
        # _adjust_overlay_visible stuck True -- which also broke the *next*
        # gallery->single click, since the app still believed it was editing.
        #
        # NOT _adjust_panel_active(): every caller here already flips
        # self.view_mode to "gallery" before calling _show_gallery_view(), and
        # _adjust_panel_active() gates on view_mode == "single" -- so that
        # check always evaluated False by the time it ran, silently no-op'ing
        # this entire fix (the bug it was meant to fix kept recurring).
        # Check the underlying overlay/panel state directly instead.
        panel = getattr(self, "single_image_adjust_panel", None)
        if getattr(self, "_adjust_overlay_visible", False) and panel is not None and panel.isVisible():
            self._close_adjust_panel_from_ui()

        # Hide single view before touching GPU/full-res buffers (Windows GL abort otherwise).
        if hasattr(self, 'single_view_container') and self.single_view_container:
            self.single_view_container.hide()
        else:
            self.scroll_area.hide()
        if hasattr(self, "compare_widget") and self.compare_widget:
            self.compare_widget.hide()
        # Let Qt finish hiding the single-view GL surface before teardown (Windows).
        release_delay_ms = 50 if sys.platform == "win32" else 0
        QTimer.singleShot(
            release_delay_ms, self._release_single_view_heavy_buffers_for_gallery
        )
        # Bottom chrome (sort/search/slideshow vs burst back-to-gallery) handled below.
        
        # In gallery mode: hide per-image metadata, but keep total count visible.
        if hasattr(self, 'status_bar'):
            self.status_bar.show()  # Keep status_bar visible to show sort button
            self.status_bar.showMessage("")  # Clear message
        if hasattr(self, 'status_metadata_label'):
            self._apply_top_metadata_text(self._gallery_top_metadata_label())
        if hasattr(self, 'status_counter_label'):
            self._update_gallery_counter()
        self._ensure_gallery_search_collapsed()
        if not self._is_gallery_search_indexing_active():
            self._clear_stale_gallery_search_index_progress()
        elif (
            getattr(self, "_search_panel_expanded", False)
            and getattr(self, "_gallery_search_show_index_progress", False)
        ):
            progress = (getattr(self, "_gallery_search_status_full", "") or "").strip()
            if progress:
                self._set_gallery_search_status(progress)
        if self._search_panel_expanded and hasattr(self, "search_expand_layout") and hasattr(
            self, "gallery_search_panel"
        ):
            self.search_expand_layout.setCurrentWidget(self.gallery_search_panel)
        # Show size slider in gallery mode; sort/search/slideshow vs burst back via chrome sync.
        if hasattr(self, 'size_slider'):
            self.size_slider.show()
        self._sync_burst_group_bottom_chrome()
        # Single-image actions stay in update_status_bar for single mode only; hide here
        # because we do not call update_status_bar() when entering gallery (counter text differs).
        if hasattr(self, "share_bottom_button"):
            self._sync_share_button_visibility()
        self._sync_bookmark_indicator()
        self._sync_slideshow_button_visibility()
        self._sync_burst_grouping_button_visibility()
        self._sync_compare_button_visibility()
        if hasattr(self, "rotate_bottom_button"):
            self.rotate_bottom_button.hide()
        if hasattr(self, "adjust_bottom_button"):
            self.adjust_bottom_button.hide()
        if hasattr(self, "raw_toggle_button"):
            self.raw_toggle_button.hide()
        if hasattr(self, "edr_toggle_button"):
            self.edr_toggle_button.hide()
        self._schedule_search_expand_overlay_sync()
        
        if hasattr(self, "gallery_scroll") and self.gallery_scroll is not None:
            self.gallery_scroll.setWidgetResizable(False)

        # Show gallery
        self.gallery_widget.show()
        self.gallery_widget.raise_()
        self._position_gallery_frame_grip()
        if hasattr(self, "gallery_justified") and self.gallery_justified:
            gj = self.gallery_justified
            if hasattr(gj, "prepare_gallery_display"):
                QTimer.singleShot(0, gj.prepare_gallery_display)
        
        # Update gallery content
        QTimer.singleShot(50, self._update_gallery_view)
        QTimer.singleShot(120, self._refresh_gallery_bookmark_visuals)
        QTimer.singleShot(0, self._restore_keyboard_focus)
        logger.debug("[MODESWITCH] _show_gallery_view scheduled gallery update")

    def _remove_orphan_gallery_containers(self) -> None:
        """Drop extra gallery shells left in the central layout (defensive)."""
        cw = self.centralWidget()
        if cw is None:
            return
        layout = cw.layout()
        if layout is None:
            return
        keep = getattr(self, "gallery_widget", None)
        for i in range(layout.count() - 1, -1, -1):
            item = layout.itemAt(i)
            if item is None:
                continue
            w = item.widget()
            if w is None or w is keep:
                continue
            if w.objectName() == "rawviewer_gallery_container":
                layout.removeWidget(w)
                w.deleteLater()

    def _ensure_gallery_widget(self) -> bool:
        """Create the gallery UI once; never stack duplicate containers."""
        self._remove_orphan_gallery_containers()
        existing = getattr(self, "gallery_widget", None)
        if existing is not None:
            try:
                layout = self.centralWidget().layout() if self.centralWidget() else None
                if layout is not None and layout.indexOf(existing) >= 0:
                    return True
            except RuntimeError:
                self.gallery_widget = None
                self.gallery_scroll = None
                self.gallery_frame_gutter = None
                self.gallery_justified = None
        self._create_gallery_widget()
        return bool(getattr(self, "gallery_widget", None))

    def _create_gallery_widget(self):
        """Create the gallery view widget - based on JustifiedGallery reference code"""
        if getattr(self, "gallery_widget", None) is not None:
            return
        from PyQt6.QtWidgets import QWidget, QVBoxLayout, QScrollArea

        # Create gallery widget container
        gallery_container = QWidget()
        gallery_container.setObjectName("rawviewer_gallery_container")
        gallery_container.setStyleSheet(f"""
            QWidget {{
                background-color: {theme.VOID};
            }}
        """)
        gallery_container.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)
        gallery_layout = QVBoxLayout(gallery_container)
        gallery_layout.setContentsMargins(0, 0, 0, 0)
        gallery_layout.setSpacing(0)

        # Create scroll area for gallery
        gallery_scroll = QScrollArea()
        # False: widget must keep full content height so 1000s of rows scroll correctly.
        gallery_scroll.setWidgetResizable(False)
        gallery_scroll.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)
        gallery_scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
        gallery_scroll.setVerticalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAsNeeded)
        gallery_scroll.setStyleSheet(f"""
            QScrollArea {{
                border: none;
                background-color: {theme.VOID};
            }}
            QScrollBar:vertical {{
                background: transparent;
                width: 24px;
                margin: 0px;
                border: none;
            }}
            QScrollBar::handle:vertical {{
                background: rgba(255, 255, 255, 0.2);
                min-height: 30px;
                border-radius: 6px;
                margin: 2px 6px 2px 6px;
            }}
            QScrollBar::handle:vertical:hover {{
                background: rgba(255, 255, 255, 0.3);
            }}
            QScrollBar::handle:vertical:pressed {{
                background: rgba(255, 255, 255, 0.4);
            }}
            QScrollBar::add-line:vertical,
            QScrollBar::sub-line:vertical {{
                height: 0px;
                width: 0px;
            }}
            QScrollBar::add-page:vertical,
            QScrollBar::sub-page:vertical {{
                background: transparent;
            }}
        """)

        # Create optimized justified gallery widget from rawviewer_ui module.
        justified_gallery = ExternalJustifiedGallery([], self)  # Empty list initially, will be populated
        
        # Restore saved row height from settings
        try:
            settings = self.get_settings()
            saved_row_height = int(settings.value("gallery_row_height", 220))
            saved_row_height = max(220, min(500, saved_row_height))
            justified_gallery.TARGET_ROW_HEIGHT = saved_row_height
        except Exception:
            pass

        justified_gallery.installEventFilter(self)
        gallery_scroll.setWidget(justified_gallery)
        gallery_layout.addWidget(gallery_scroll)

        # Overlay on the scrollbar's frame-side margin — captures resize drags without
        # shrinking the scroll area (layout gutter was stealing 6px from the viewport).
        gallery_grip = QWidget(gallery_container)
        gallery_grip.setStyleSheet("background: transparent;")
        gallery_grip.setMouseTracking(True)
        gallery_grip.hide()

        # Insert gallery widget into main layout (after single-image row).
        # The anchor must be a DIRECT child of main_layout: since the Adjust
        # panel moved single_view_container inside single_view_splitter,
        # indexOf(single_view_container) returns -1, and insertWidget(-1 + 1)
        # placed the gallery at index 0 -- ABOVE the custom title bar. In
        # gallery mode the container then filled the window from the top and
        # the title bar (min/max/close) was pushed out of its expected spot:
        # "top bar missing, cannot close or maximize the app".
        main_layout = self.centralWidget().layout()
        scroll_index = -1
        for anchor in (
            getattr(self, "single_view_splitter", None),
            getattr(self, "single_view_container", None),
            getattr(self, "scroll_area", None),
        ):
            if anchor is not None:
                scroll_index = main_layout.indexOf(anchor)
                if scroll_index >= 0:
                    break
        if scroll_index < 0:
            # No known anchor found: append at the end rather than clobbering
            # index 0 (the title bar row).
            scroll_index = main_layout.count() - 1
        cast(Any, main_layout).insertWidget(scroll_index + 1, gallery_container)

        self.gallery_widget = gallery_container
        self.gallery_scroll = gallery_scroll
        self.gallery_frame_gutter = gallery_grip
        self.gallery_justified = justified_gallery
        if hasattr(self, "size_slider") and self.size_slider is not None:
            self.gallery_justified.TARGET_ROW_HEIGHT = self.size_slider.value()
        gallery_scroll.setMouseTracking(True)
        gallery_scroll.viewport().setMouseTracking(True)
        gallery_scroll.installEventFilter(self)
        gallery_scroll.viewport().installEventFilter(self)
        gallery_grip.installEventFilter(self)
        v_scrollbar = gallery_scroll.verticalScrollBar()
        v_scrollbar.setMouseTracking(True)
        v_scrollbar.installEventFilter(self)
        gallery_container.installEventFilter(self)
        self._position_gallery_frame_grip()
        self._setup_file_drop_targets()

        # Hide it initially - it will be shown by _show_gallery_view() when needed
        gallery_container.hide()

        # NOTE: rawviewer_ui.gallery_view.JustifiedGallery already wires scrollbar events
        # internally (valueChanged + sliderPressed/Released). Avoid duplicate connections
        # here; they can trigger redundant scheduling and visible scroll lag.

    def _on_zoom_slider_pressed(self):
        if hasattr(self, "gallery_justified") and self.gallery_justified:
            self.gallery_justified.begin_zoom_session()

    def _on_zoom_slider_changed(self, value):
        if hasattr(self, "gallery_justified") and self.gallery_justified:
            gj = self.gallery_justified
            gj.apply_gallery_zoom(value)

    def _on_zoom_slider_released(self):
        if hasattr(self, "gallery_justified") and self.gallery_justified:
            value = self.size_slider.value()
            self.get_settings().setValue("gallery_row_height", value)
            if self._zoom_debounce_timer.isActive():
                self._zoom_debounce_timer.stop()
            gj = self.gallery_justified
            gj.apply_gallery_zoom(value)
            gj.end_zoom_session()

    def _rebuild_gallery_zoom(self):
        if hasattr(self, "gallery_justified") and self.gallery_justified:
            gj = self.gallery_justified
            value = self.size_slider.value()
            if not getattr(gj, "_is_zooming", False):
                gj.begin_zoom_session()
            gj.apply_gallery_zoom(value)
            gj.end_zoom_session()
            try:
                self.get_settings().setValue("gallery_row_height", value)
            except Exception:
                pass

    def _on_gallery_metadata_ready(self, meta, folder_at_request):
        """Thread-safe handler for metadata fetch completion"""
        try:
            # Clear active fetcher references now that it's done
            self._active_metadata_fetcher = None
            self._active_metadata_signals = None
            
            # Ignore if folder changed during fetch
            if getattr(self, "current_folder", None) != folder_at_request:
                return
            self._gallery_bulk_metadata = meta
            self._gallery_metadata_fetch_in_progress = False
            self._bump_gallery_rating_presence_epoch()
            self._rebuild_burst_groups()
            if getattr(self, "view_mode", "") == "gallery":
                self._sync_gallery_rating_filter_stars()
            
            if hasattr(self, 'gallery_justified') and self.gallery_justified and self.image_files:
                try:
                    import logging
                    logger = logging.getLogger(__name__)
                    current_file = getattr(self, "current_file_path", None)

                    # Only re-sort if the EXIF refinement hasn't already applied a correct order.
                    # The refinement uses the semantic index (6889 entries) and produces authentic
                    # capture-time order.  This fetch used probe_uncached=False (cache only, ~3 entries)
                    # so its sort would degrade to mtime order and overwrite the correct EXIF order.
                    current_gen = getattr(self, "_folder_load_generation", None)
                    refinement_applied = (
                        getattr(self, "_folder_sort_refinement_applied_token", None) == current_gen
                    )
                    refinement_pending = (
                        getattr(self, "_folder_sort_refinement_token", None) == current_gen
                        and not refinement_applied
                    )
                    if not refinement_applied and not refinement_pending:
                        newest_first = self.get_sort_preference()
                        file_stats = getattr(self, "_quick_folder_file_stats", None)
                        sorted_files, merged_meta = self.sort_files_by_capture_time(
                            self.image_files,
                            newest_first=newest_first,
                            file_stats=file_stats,
                            probe_uncached=False,
                            folder_path=folder_at_request,
                        )
                        if merged_meta:
                            meta.update(merged_meta)
                        if sorted_files != self.image_files:
                            self.image_files = sorted_files
                            if current_file in self.image_files:
                                self.current_file_index = self.image_files.index(current_file)
                            self.update_status_bar()
                    else:
                        logger.info(
                            "[GALLERY] Background metadata ready: deferring cache-only re-sort "
                            "(refinement applied=%s pending=%s)",
                            refinement_applied,
                            refinement_pending,
                        )

                    self._sync_gallery_to_folder_files(
                        meta,
                        scroll_to_current=getattr(self, "view_mode", "") != "gallery",
                        force=not refinement_pending,
                    )
                    logger.info(f"[GALLERY] Background metadata ready: {len(meta)} items, gallery refreshed")
                except Exception as e:
                    import logging
                    logger = logging.getLogger(__name__)
                    logger.error(f"[GALLERY] Error refreshing gallery with metadata: {e}")
        except Exception as e:
            import logging
            logger = logging.getLogger(__name__)
            logger.error(f"[GALLERY] Critical error in _on_gallery_metadata_ready: {e}")
        finally:
            self._gallery_metadata_fetch_in_progress = False

    def _gallery_layout_seed_paths(self, files: list, anchor_path: str | None) -> list:
        """Subset of paths for layout metadata pre-seed (avoid 5k+ SQLite lookups on gallery open)."""
        if not files:
            return []
        limit = self._GALLERY_LAYOUT_META_SEED_MAX
        if len(files) <= limit:
            return files
        if not anchor_path:
            return files[:limit]
        anchor_norm = _norm_path(anchor_path)
        center = 0
        for i, fp in enumerate(files):
            if _norm_path(fp) == anchor_norm:
                center = i
                break
        half = limit // 2
        start = max(0, center - half)
        end = min(len(files), start + limit)
        start = max(0, end - limit)
        return files[start:end]

    def _update_gallery_view(self):
            """Update gallery view - using JustifiedGallery"""
            import logging
            import time
            from PyQt6.QtCore import QTimer
            logger = logging.getLogger(__name__)
            if getattr(self, "view_mode", "") != "gallery":
                logger.debug(
                    "[GALLERY] _update_gallery_view skipped; view_mode=%s",
                    getattr(self, "view_mode", ""),
                )
                return
            logger.debug("[MODESWITCH] _update_gallery_view called; widget=%s justified=%s files=%d",
                           bool(self.gallery_widget), bool(self.gallery_justified), len(self.image_files))
            start_time = time.time()
            logger.info("[GALLERY] ========== _update_gallery_view() STARTED ==========")
            self._update_gallery_counter()
            
            if not self.gallery_widget or not self.gallery_justified:
                logger.info("[GALLERY] Gallery widget not available, returning")
                return
            self._sync_gallery_scrollbar_policy()
            if not self.image_files:
                logger.info("[GALLERY] No image files for gallery update, returning")
                query = getattr(self, "_last_semantic_query", "") or ""
                if query.strip():
                    bulk_meta = getattr(self, "_gallery_bulk_metadata", None)
                    self.gallery_justified.set_images(
                        [], bulk_meta if bulk_meta else None
                    )
                    self.gallery_justified.show_empty_message("No matching images")
                return

            # IMPORTANT: Switching to gallery should be instant.
            # Do NOT block the UI thread on metadata fetch for thousands of files.
            # 1) Show gallery immediately with a fast layout (default aspect ratios or cached).
            bulk_metadata = getattr(self, '_gallery_bulk_metadata', None) or {}
            try:
                # Pre-seed layout metadata from the fast semantic index if available
                # to prevent the gallery from flashing as async EXIF arrives
                try:
                    idx = self._get_semantic_index()
                    if idx and self.image_files:
                        layout_meta = idx.get_layout_metadata_for_paths(self.image_files)
                        if layout_meta:
                            for fp, meta in layout_meta.items():
                                if fp not in bulk_metadata:
                                    bulk_metadata[fp] = {}
                                # Don't overwrite if EXIF already arrived
                                if "original_width" not in bulk_metadata[fp] and (
                                    meta.get("original_width") or meta.get("width")
                                ):
                                    if meta.get("original_width"):
                                        bulk_metadata[fp]["original_width"] = int(
                                            meta["original_width"]
                                        )
                                        bulk_metadata[fp]["original_height"] = int(
                                            meta.get("original_height") or 0
                                        )
                                        bulk_metadata[fp]["orientation"] = int(
                                            meta.get("orientation") or 1
                                        )
                                    else:
                                        from common_image_loader import exif_display_dimensions

                                        w = int(meta.get("width") or 0)
                                        h = int(meta.get("height") or 0)
                                        o = int(meta.get("orientation") or 1)
                                        bulk_metadata[fp]["original_width"] = w
                                        bulk_metadata[fp]["original_height"] = h
                                        bulk_metadata[fp]["orientation"] = o
                except Exception as ex:
                    logger.warning(f"[GALLERY] Could not pre-seed semantic metadata: {ex}")

                self._maybe_clear_empty_bookmark_filter()
                self._maybe_clear_empty_rating_filter()
                self._rebuild_burst_groups()
                display_files = self._gallery_files_for_display()
                filter_active = bool(
                    getattr(self, "_gallery_bookmark_filter_active", False)
                ) or int(getattr(self, "_gallery_rating_filter_min", 0) or 0) > 0
                if not display_files and filter_active:
                    self.gallery_justified.set_images(
                        [], bulk_metadata if bulk_metadata else None
                    )
                    self.gallery_justified.show_empty_message(
                        f"No {self._gallery_scope_filter_description()}"
                    )
                else:
                    if hasattr(self.gallery_justified, "hide_empty_message"):
                        self.gallery_justified.hide_empty_message()
                    gj = self.gallery_justified
                    display_files = self._gallery_files_for_display()
                    preserve_viewport = bool(
                        gj
                        and gj._layout_matches_current_images(display_files)
                        and getattr(gj, "_gallery_layout_items", None)
                    )
                    if not preserve_viewport:
                        self._scroll_gallery_to_current_file(backup=False)
                    self.gallery_justified.set_images(
                        display_files, bulk_metadata if bulk_metadata else None
                    )
                    # Preserve path: scroll position is already correct — calling
                    # scroll_to_file() would reset attempt counters and park
                    # load_visible behind entry-scroll retries (blank gallery).
                    if not preserve_viewport:
                        self._scroll_gallery_to_current_file()
                # Avoid forced rebuild loops; set_images() already schedules build/layout.
                # Only nudge visible-load passes after initial layout is expected ready.
                self._warm_gallery_from_filmstrip_cache()
                if hasattr(self.gallery_justified, "sync_visual_rotations"):
                    # Fast path: layout already built (same folder/order). Full rebuild path
                    # syncs at end of build_gallery() once _path_to_indices exists.
                    self.gallery_justified.sync_visual_rotations()
                current_file = getattr(self, "current_file_path", None)
                if (
                    current_file
                    and hasattr(self.gallery_justified, "apply_visual_rotation_for_path")
                ):
                    self.gallery_justified.apply_visual_rotation_for_path(current_file)
                file_count = len(self.image_files or [])
                first_load_ms = min(200, max(80, 80 + file_count // 120))
                gj = self.gallery_justified
                if hasattr(gj, "_request_load_visible_images"):
                    gj._request_load_visible_images(0)
                    gj._request_load_visible_images(first_load_ms)
                    gj._request_load_visible_images(first_load_ms + 500)
                else:
                    QTimer.singleShot(first_load_ms, gj.load_visible_images)
                    QTimer.singleShot(first_load_ms + 500, gj.load_visible_images)
            except Exception as e:
                logger.exception(f"[GALLERY] set_images failed: {e}")
                self.show_error(
                    "Gallery Error",
                    f"Could not build the gallery view:\n{e}",
                )
                return

            # 2) If metadata is missing, fetch it in the background and refresh once ready.
            if not bulk_metadata and not getattr(self, "_gallery_metadata_fetch_in_progress", False):
                self._gallery_metadata_fetch_in_progress = True
                folder_at_request = getattr(self, "current_folder", None)
                files_snapshot = list(self.image_files)

                from PyQt6.QtCore import QRunnable, QThreadPool

                # Create signal carrier for this specific fetch
                signals = GalleryMetadataSignals()
                signals.ready.connect(self._on_gallery_metadata_ready)
                
                # Store references to prevent garbage collection while thread is running
                self._active_metadata_signals = signals

                class _GalleryMetadataFetch(QRunnable):
                    def __init__(self_inner, files, signals, folder_path):
                        super().__init__()
                        self_inner.files = files
                        self_inner.signals = signals
                        # Ensure folder_path is string (PyQt signals are strict)
                        self_inner.folder_path = folder_path if folder_path is not None else ""
                        
                    def run(self_inner):
                        try:
                            from image_cache import get_image_cache
                            cache = get_image_cache()
                            # OPTIMIZATION: In large folders, avoid hitting the disk for every file
                            # in a background thread while the gallery is also loading thumbnails.
                            # Just use what's in the SQLite cache (opportunistic like v1.6.0).
                            meta = cache.get_multiple_exif(self_inner.files, fast_mode=True)
                            try:
                                from PyQt6 import sip
                                if not sip.isdeleted(self_inner.signals):
                                    self_inner.signals.ready.emit(meta, self_inner.folder_path)
                            except Exception:
                                pass
                        except Exception as e:
                            import logging
                            logger = logging.getLogger(__name__)
                            logger.error(f"[GALLERY] Metadata fetch error: {e}")
                            # Emit empty meta but still valid folder path string
                            try:
                                from PyQt6 import sip
                                if not sip.isdeleted(self_inner.signals):
                                    self_inner.signals.ready.emit({}, self_inner.folder_path)
                            except Exception:
                                pass

                fetcher = _GalleryMetadataFetch(files_snapshot, signals, folder_at_request)
                self._active_metadata_fetcher = fetcher
                _get_bg_thread_pool().start(fetcher)
            
            total_time = time.time() - start_time
            logger.info(f"[GALLERY] ========== GALLERY LAYOUT COMPLETED in {total_time:.3f}s ==========")
    
    def _add_gallery_row(self, row_items, available_width, content_width, row_height, row_spacing):
            """Add a single row - based on reference code add_row method"""
            from PyQt6.QtWidgets import QWidget, QHBoxLayout
            
            row_widget = QWidget()
            row_layout = QHBoxLayout(row_widget)
            row_layout.setContentsMargins(0, 0, 0, 0)
            row_layout.setSpacing(0)
            
            # Remaining space after placing all thumbnails
            free_space = max(0, available_width - content_width)
            
            # Spacing distributed evenly between items
            gaps = len(row_items) - 1 if len(row_items) > 1 else 1
            # Limit extra padding to prevent excessive spacing
            # Use minimum of calculated padding or a maximum value (e.g., 8px)
            extra_padding = min(free_space // gaps, 8) if gaps > 0 else 0
            
            for i, (file_path, w) in enumerate(row_items):
                # Create thumbnail label (will be loaded async)
                thumb_label = ThumbnailLabel()
                thumb_label.file_path = file_path
                
                if not hasattr(self, '_gallery_thumb_labels'):
                    self._gallery_thumb_labels = {}
                self._gallery_thumb_labels[file_path] = thumb_label
                
                # Make clickable
                thumb_label.clicked.connect(self._gallery_item_clicked)
                
                # Load pixmap and scale it
                pixmap = self._get_gallery_pixmap(file_path)
                if pixmap and not pixmap.isNull():
                    # Scale to fixed height while preserving aspect ratio (like reference)
                    # Ensure dimensions are at least 1px to prevent crash
                    safe_width = max(1, w)
                    safe_height = max(1, row_height)
                    resized = pixmap.scaled(
                        QSize(safe_width, safe_height),
                        Qt.AspectRatioMode.KeepAspectRatio,
                        Qt.TransformationMode.SmoothTransformation
                    )
                    thumb_label.setFixedSize(resized.size())  # CRITICAL: Like reference code
                    thumb_label.setPixmap(resized)
                    thumb_label.set_original_pixmap(pixmap)
                else:
                    # Placeholder size, will be updated when loaded
                    thumb_label.setFixedSize(w, row_height)
                    # Load asynchronously
                    from PyQt6.QtCore import QTimer
                    QTimer.singleShot(50, lambda fp=file_path, tl=thumb_label: self._load_gallery_thumbnail_simple(fp, tl))
                
                row_layout.addWidget(thumb_label)
                
                # Apply padding after each item (except last) - like reference code
                if i < len(row_items) - 1:
                    row_layout.addSpacing(row_spacing + extra_padding)
            
            self.gallery_content_layout.addWidget(row_widget)
    
    def _load_gallery_thumbnail_simple(self, file_path, thumb_label):
            """Load thumbnail simply - based on reference code"""
            
            pixmap = self._get_gallery_pixmap(file_path)
            if not pixmap or pixmap.isNull():
                # Try async load
                self._load_gallery_pixmap_async(file_path)
                return
            
            # Get aspect ratio
            aspect = pixmap.width() / pixmap.height() if pixmap.height() > 0 else 4.0 / 3.0
            thumb_width = int(self.gallery_row_height * aspect)
            
            # Scale to fixed height while preserving aspect ratio (like reference)
            # Ensure dimensions are at least 1px to prevent crash
            safe_width = max(1, thumb_width)
            safe_height = max(1, self.gallery_row_height)
            resized = pixmap.scaled(
                QSize(safe_width, safe_height),
                Qt.AspectRatioMode.KeepAspectRatio,
                Qt.TransformationMode.SmoothTransformation
            )
            
            # CRITICAL: Like reference code - thumb.setFixedSize(resized.size())
            thumb_label.setFixedSize(resized.size())
            thumb_label.setPixmap(resized)
            thumb_label.set_original_pixmap(pixmap)
            
            if file_path in self._gallery_load_tracking:
                self._gallery_load_tracking[file_path]['loaded'] = True
                self._gallery_load_tracking[file_path]['displayed'] = True
    
    def _get_gallery_aspect_ratio(self, file_path):
        """
        Get aspect ratio for a file without loading the full image.
        Optimized to use cache, then EXIF tags, then RAW metadata.
        """
        import os
        import logging
        logger = logging.getLogger(__name__)
        
        # 1. Check in-memory cache
        if file_path in self.gallery_aspect_cache:
            return self.gallery_aspect_cache[file_path]
        
        # 2. Try EXIF cache (fast)
        try:
            exif_data = self.image_cache.get_exif(file_path)
            if exif_data:
                w = exif_data.get('original_width')
                h = exif_data.get('original_height')
                orientation = exif_data.get('orientation', 1)
                
                if w and h and h > 0:
                    # Respect orientation (5,6,7,8 are rotated formats)
                    if orientation in (5, 6, 7, 8):
                        w, h = h, w
                    aspect = w / h
                    self.gallery_aspect_cache[file_path] = aspect
                    return aspect
        except Exception:
            pass
            
        # 3. Extract dimensions and orientation directly from file
        ext = os.path.splitext(file_path)[1].lower()
        raw_extensions = {'.arw', '.cr2', '.nef', '.raf', '.orf', '.dng', '.cr3', '.rw2', '.rwl', '.srw', 
                        '.pef', '.x3f', '.3fr', '.fff', '.iiq', '.cap', '.erf', '.mef', '.mos', '.nrw', '.srf'}
        is_raw = ext in raw_extensions
        
        # A. Try EXIF (pyexiv2 preferred, else exifread) for JPEG/TIFF and some RAW formats
        exif_likely_exts = {'.jpg', '.jpeg', '.tif', '.tiff', '.arw', '.cr2', '.nef', '.raf', '.orf', '.dng', '.cr3', '.heic', '.heif'}
        if ext in exif_likely_exts:
            try:
                tags = process_file_from_path(
                    file_path, details=False, stop_tag="EXIF ExifImageWidth"
                )

                # Search for width and height in various tags
                w = h = None
                for w_tag in ['EXIF ExifImageWidth', 'Image ImageWidth']:
                    if w_tag in tags:
                        try:
                            w = int(str(tags[w_tag]))
                            break
                        except Exception:
                            pass

                for h_tag in ['EXIF ExifImageLength', 'Image ImageLength']:
                    if h_tag in tags:
                        try:
                            h = int(str(tags[h_tag]))
                            break
                        except Exception:
                            pass

                # Handle Orientation
                orientation = 1
                if 'Image Orientation' in tags:
                    try:
                        val = tags['Image Orientation'].values[0]
                        # Handle both integer and string orientation values
                        if isinstance(val, int):
                            orientation = val
                        else:
                            # Map common string orientations to numbers if necessary
                            # Most exifread results for 'Orientation' are already integers in values[0]
                            orientation = int(str(val))
                    except Exception:
                        pass

                if w and h and h > 0:
                    real_w, real_h = (h, w) if orientation in (5, 6, 7, 8) else (w, h)
                    aspect = real_w / real_h
                    self.gallery_aspect_cache[file_path] = aspect

                    # Update cache with un-swapped dimensions but correct orientation
                    try:
                        cached_exif = self.image_cache.get_exif(file_path) or {}
                        cached_exif['original_width'] = w
                        cached_exif['original_height'] = h
                        cached_exif['orientation'] = orientation
                        self.image_cache.put_exif(file_path, cached_exif)
                    except Exception:
                        pass
                    return aspect
            except Exception:
                pass

        # B. Try rawpy for RAW specific metadata (more reliable for some cameras)
        if is_raw:
            try:
                import rawpy
                with rawpy.imread(file_path) as raw:
                    # rawpy dimensions are usually the sensor dimensions (un-rotated)
                    w, h = raw.sizes.width, raw.sizes.height
                    
                    # raw.sizes.flip contains rotation info (usually 0, 3, 5, or 6)
                    # 3 = 180, 5 = 90 CCW, 6 = 90 CW
                    flip = raw.sizes.flip
                    
                    if flip in (5, 6): # Rotated 90 degrees
                        real_w, real_h = h, w
                        aspect = real_w / real_h
                    else:
                        aspect = w / h
                    
                    self.gallery_aspect_cache[file_path] = aspect
                    # Update cache
                    try:
                        cached_exif = self.image_cache.get_exif(file_path) or {}
                        cached_exif['original_width'] = w
                        cached_exif['original_height'] = h
                        # Map rawpy flip to EXIF orientation for consistency if possible
                        # 0->1, 3->3, 6->6, 5->8 (approximate)
                        if flip == 6: cached_exif['orientation'] = 6
                        elif flip == 3: cached_exif['orientation'] = 3
                        elif flip == 5: cached_exif['orientation'] = 8
                        else: cached_exif['orientation'] = 1
                        self.image_cache.put_exif(file_path, cached_exif)
                    except Exception: pass
                    return aspect
            except Exception:
                pass

        # C. Try PIL fallback (for TIFF/JPEG)
        try:
            from PIL import Image
            with Image.open(file_path) as img:
                w, h = img.size
                # orientation handling in PIL
                orientation = 1
                try:
                    exif_getter = getattr(img, "_getexif", None)
                    exif = exif_getter() if callable(exif_getter) else None
                    if isinstance(exif, dict):
                        orientation = int(exif.get(274, 1))  # 274 is Orientation tag
                except Exception: pass
                
                if h > 0:
                    real_w, real_h = (h, w) if orientation in (5, 6, 7, 8) else (w, h)
                    aspect = real_w / real_h
                    self.gallery_aspect_cache[file_path] = aspect
                    return aspect
        except Exception:
            pass
            
        return 1.333  # Final fallback
    
    def _numpy_to_qpixmap(self, numpy_array):
        """
        Convert numpy array to QPixmap safely.
        Handles all edge cases and ensures correct format.
        """
        import logging
        logger = logging.getLogger(__name__)
        
        try:
            if numpy_array is None:
                return None
            
            # Get shape
            shape = numpy_array.shape
            if len(shape) < 2:
                logger.warning(f"[GALLERY] Invalid numpy array shape: {shape}, expected at least 2D (H, W)")
                return None
            
            height, width = shape[0], shape[1]
            channels = shape[2] if len(shape) > 2 else 1

            if channels == 1:
                plane = numpy_array.reshape(height, width)
                numpy_array = np.stack([plane, plane, plane], axis=-1)
                channels = 3

            if channels not in [3, 4]:
                logger.warning(f"[GALLERY] Unsupported channel count: {channels}, expected 1, 3, or 4")
                return None
            
            if width <= 0 or height <= 0:
                logger.warning(f"[GALLERY] Invalid dimensions: {width}x{height}")
                return None
            
            # Ensure contiguous and uint8
            if not numpy_array.flags['C_CONTIGUOUS']:
                numpy_array = np.ascontiguousarray(numpy_array)
            
            if numpy_array.dtype == np.uint16:
                numpy_array = (numpy_array / 257.0).astype(np.uint8)
            elif np.issubdtype(numpy_array.dtype, np.floating):
                from raw_tone_recovery import _encode_srgb8

                numpy_array = _encode_srgb8(
                    np.clip(numpy_array.astype(np.float32), 0.0, None)
                )
            elif numpy_array.dtype != np.uint8:
                numpy_array = np.clip(numpy_array, 0, 255).astype(np.uint8)
            
            # Calculate bytes per line (must be exact, no padding)
            bytes_per_line = channels * width
            
            # Wrap the numpy buffer directly — avoids an extra full-frame
            # tobytes() allocation. QImage does not own the memory, so
            # .copy() once into Qt-owned storage before building the pixmap.
            qimage = QImage(
                numpy_array.data,
                width,
                height,
                bytes_per_line,
                QImage.Format.Format_RGB888,
            ).copy()
            
            if qimage.isNull():
                logger.warning(f"[GALLERY] Failed to create QImage from numpy array {width}x{height}")
                return None
            
            # Convert to QPixmap
            pixmap = QPixmap.fromImage(qimage)
            
            if pixmap.isNull():
                logger.warning("[GALLERY] Failed to create QPixmap from QImage")
                return None
            
            return pixmap
            
        except Exception as e:
            logger.warning(f"[GALLERY] Error converting numpy to QPixmap: {e}")
            import traceback
            logger.debug(f"Traceback: {traceback.format_exc()}")
            return None
    
    def _extract_embedded_preview(self, file_path):
        """Extract oriented RAW preview for gallery fallbacks (shared loader)."""
        from common_image_loader import load_raw_preview_pixmap

        pixmap = load_raw_preview_pixmap(file_path, max_size=1024)
        return pixmap if pixmap is not None and not pixmap.isNull() else None
    
    def _get_gallery_pixmap(self, file_path):
        """Get pixmap for gallery view, loading if necessary - optimized for performance"""
        import os
        import logging
        logger = logging.getLogger(__name__)
        
        # Check cache first (fastest)
        if file_path in self.gallery_pixmaps:
            pixmap = self.gallery_pixmaps[file_path]
            if pixmap and not pixmap.isNull():
                return pixmap
        
        # Try to load from image cache (fast, already processed)
        # This includes pixmaps from single view mode, enabling smooth switching
        try:
            cached_pixmap = self.image_cache.get_pixmap(file_path)
            if cached_pixmap and not cached_pixmap.isNull():
                # Also store in gallery_pixmaps for faster subsequent access
                self.gallery_pixmaps[file_path] = cached_pixmap
                # Update aspect cache
                aspect = cached_pixmap.width() / cached_pixmap.height() if cached_pixmap.height() > 0 else 4.0 / 3.0
                self.gallery_aspect_cache[file_path] = aspect
                logger.debug(f"[GALLERY] Using cached pixmap from single view: {os.path.basename(file_path)}")
                return cached_pixmap
        except Exception as e:
            logger.debug(f"Error getting pixmap from cache for {file_path}: {e}")
        
        # Try to get thumbnail from thumbnail cache (faster than extracting)
        try:
            thumbnail_data = self.image_cache.get_thumbnail(file_path)
            if thumbnail_data is not None:
                # Use unified conversion method
                pixmap = self._numpy_to_qpixmap(thumbnail_data)
                if pixmap and not pixmap.isNull():
                    self.gallery_pixmaps[file_path] = pixmap
                    # Also cache in global image cache for smooth switching between views
                    # DO NOT cache in global image cache - this avoids polluting it with small gallery-sized pixmaps
                    # if they are just thumbnails.
                    # self.image_cache.put_pixmap(file_path, pixmap)
                    # Update aspect cache
                    aspect = pixmap.width() / pixmap.height() if pixmap.height() > 0 else 4.0 / 3.0
                    self.gallery_aspect_cache[file_path] = aspect
                    return pixmap
        except Exception as e:
            logger.warning(f"Error getting thumbnail from cache for {file_path}: {e}")
            import traceback
            logger.debug(f"Traceback: {traceback.format_exc()}")
        
        # For RAW files, try to extract embedded JPEG preview (fast)
        try:
            if os.path.exists(file_path):
                file_ext = os.path.splitext(file_path)[1].lower()
                raw_extensions = ['.arw', '.cr2', '.nef', '.raf', '.orf', '.dng', '.cr3', '.rw2', '.rwl', '.srw']
                if file_ext in raw_extensions:
                    pixmap = self._extract_embedded_preview(file_path)
                    if pixmap and not pixmap.isNull():
                        self.gallery_pixmaps[file_path] = pixmap
                        # Also cache in global image cache for smooth switching between views
                        # DO NOT cache in global image cache - this avoids polluting it with small previews
                        # self.image_cache.put_pixmap(file_path, pixmap)
                        # Update aspect cache
                        aspect = pixmap.width() / pixmap.height() if pixmap.height() > 0 else 4.0 / 3.0
                        self.gallery_aspect_cache[file_path] = aspect
                        logger.debug(f"[GALLERY] Using embedded preview for gallery: {os.path.basename(file_path)}")
                        return pixmap
        except Exception as e:
            logger.debug(f"Error extracting embedded preview from RAW {file_path}: {e}")
        
        # For non-RAW files, try direct QPixmap load (fast for JPEG/PNG)
        try:
            if os.path.exists(file_path):
                file_ext = os.path.splitext(file_path)[1].lower()
                if file_ext not in ['.arw', '.cr2', '.nef', '.raf', '.orf', '.dng', '.cr3', '.rw2', '.rwl', '.srw']:
                    pixmap = self._load_pixmap_safe(file_path)
                    if not pixmap.isNull():
                        self.gallery_pixmaps[file_path] = pixmap
                        # Also cache in global image cache for smooth switching between views
                        # DO NOT cache in global image cache - this avoids polluting it with small previews
                        # self.image_cache.put_pixmap(file_path, pixmap)
                        # Update aspect cache
                        aspect = pixmap.width() / pixmap.height() if pixmap.height() > 0 else 4.0 / 3.0
                        self.gallery_aspect_cache[file_path] = aspect
                        return pixmap
        except Exception as e:
            logger.debug(f"Error loading pixmap from file {file_path}: {e}")
        
        # Return None - will be loaded asynchronously
        # This allows layout to proceed without blocking
        return None
    
    # GALLERY FUNCTIONALITY COMMENTED OUT
    # def _add_grid_row(self, row_files, available_width, row_height, item_spacing, row_index=0, start_index=0):
    #     """Create a simple grid row with fixed height - basic gallery layout"""
    #     pass  # Gallery functionality disabled
        
        # Create row widget with fixed height
        row_widget = QWidget()
        row_widget.setFixedHeight(row_height)
        row_widget.setFixedWidth(available_width)
        row_widget.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)
        row_widget.setStyleSheet(f"""
            QWidget {{
                background-color: {theme.VOID};
                margin: 0px;
                padding: 0px;
            }}
        """)
        
        row_layout = QHBoxLayout(row_widget)
        row_layout.setContentsMargins(0, 0, 0, 0)
        row_layout.setSpacing(item_spacing)
        
        # Calculate item width (distribute available space evenly)
        num_items = len(row_files)
        total_spacing = item_spacing * (num_items - 1) if num_items > 1 else 0
        available_for_items = available_width - total_spacing
        item_width = int(available_for_items / num_items) if num_items > 0 else available_width
        
        for item_index, file_path in enumerate(row_files):
            # Create thumbnail label
            thumb_label = ThumbnailLabel()
            thumb_label.setFixedSize(item_width, row_height)
            thumb_label.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)
            thumb_label.setStyleSheet(f"""
                QLabel {{
                    background-color: {theme.RAISED};
                    border: none;
                    margin: 0px;
                    padding: 0px;
                }}
            """)
            thumb_label.file_path = file_path
            
            # Store reference
            if not hasattr(self, '_gallery_thumb_labels'):
                self._gallery_thumb_labels = {}
            self._gallery_thumb_labels[file_path] = thumb_label
            
            # Make clickable
            thumb_label.mousePressEvent = lambda e, fp=file_path: self._gallery_item_clicked(fp)
            
            # Load thumbnail asynchronously with staggered delay to avoid blocking UI
            # Each item gets a slightly longer delay to spread out the loading
            global_index = start_index + item_index
            delay = 10 + (global_index * 5)  # Stagger delays: 10ms, 15ms, 20ms, etc.
            self._load_gallery_thumbnail_async_justified(file_path, thumb_label, item_width, row_height, delay)
            
            row_layout.addWidget(thumb_label)
        
        # Add row to gallery
        self.gallery_content_layout.addWidget(row_widget)
    
    # GALLERY FUNCTIONALITY COMMENTED OUT
    # def _add_justified_row(self, row_items, row_width, available_width, row_height, min_spacing, row_index=0):
    #     """Create a row of thumbnails with equal horizontal spacing between images"""
    #     pass  # Gallery functionality disabled
        # Calculate total width needed for all images at base scale
        total_images_width = sum(base_width for _, base_width in row_items)
        
        if total_images_width <= 0 or len(row_items) == 0:
            return
        
        # Calculate number of gaps between images (n-1 gaps for n images)
        num_gaps = len(row_items) - 1
        
        # Calculate equal spacing between images
        # Formula: available_width = scaled_total_width + (num_gaps * spacing_between)
        # We want to ensure spacing is at least min_spacing, then scale images to fit
        # If we have enough space, use min_spacing and scale images up
        # If we don't have enough space, use calculated spacing (which may be less than min_spacing)
        if num_gaps > 0:
            # Calculate maximum spacing we can use
            max_spacing = (available_width - total_images_width) / num_gaps if num_gaps > 0 else 0
            
            # Use the larger of min_spacing or calculated spacing
            # If we have enough space, use min_spacing and scale images to fill remaining space
            # If we don't have enough space, use calculated spacing (which may be less than min_spacing)
            if max_spacing >= min_spacing:
                # We have enough space, use min_spacing and scale images to fill remaining space
                total_spacing_width = min_spacing * num_gaps
                available_for_images = available_width - total_spacing_width
                scale_factor = available_for_images / total_images_width if total_images_width > 0 else 1.0
                spacing_between = min_spacing
            else:
                # Not enough space, use all available space for spacing and scale images down
                scale_factor = 1.0
                spacing_between = max_spacing if max_spacing > 0 else 0
        else:
            # Only one image, scale it to fit available width
            scale_factor = available_width / total_images_width if total_images_width > 0 else 1.0
            spacing_between = 0
        
        # Calculate row height: thumbnail height only (no histogram)
        # All items in the row should have the same total height
        first_item_height = int(row_height * scale_factor) if row_items else row_height
        total_row_height = first_item_height
        
        # Create row widget with fixed height and width to ensure no vertical spacing and no horizontal scroll
        row_widget = QWidget()
        row_widget.setFixedHeight(total_row_height)  # CRITICAL: Set fixed height to prevent spacing
        row_widget.setFixedWidth(available_width)  # CRITICAL: Set fixed width to prevent horizontal scroll
        row_widget.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)  # Prevent resizing
        row_widget.setStyleSheet(f"""
            QWidget {{
                background-color: {theme.VOID};
                margin: 0px;
                padding: 0px;
            }}
        """)
        row_layout = QHBoxLayout(row_widget)
        row_layout.setContentsMargins(0, 0, 0, 0)  # No margins
        row_layout.setSpacing(0)  # No spacing between items (we add spacers manually)
        
        for i, (file_path, base_width) in enumerate(row_items):
            # CRITICAL OPTIMIZATION: Don't load pixmap here during layout!
            # This is called for every image during layout calculation
            # Loading images synchronously here would block for 30+ seconds
            # Instead, create placeholder and load asynchronously
            
            # Compute final scaled size (maintain aspect ratio, no stretching)
            new_width = int(base_width * scale_factor)
            new_height = int(row_height * scale_factor)
            
            # Create thumbnail label
            thumb_label = ThumbnailLabel()
            # Set fixed size - this is the target size for the thumbnail
            thumb_label.setFixedSize(new_width, new_height)
            # Ensure size policy is Fixed (already set in ThumbnailLabel.__init__, but double-check)
            thumb_label.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)
            thumb_label.setStyleSheet(f"""
                QLabel {{
                    background-color: {theme.RAISED};
                    border: none;
                    margin: 0px;
                    padding: 0px;
                }}
            """)
            # setScaledContents(False) is set in ThumbnailLabel.__init__
            # We will manually scale pixmap to exact size to prevent stretching
            
            # Store file path for async loading
            thumb_label.file_path = file_path
            # Store reference to thumb_label for later updates
            if not hasattr(self, '_gallery_thumb_labels'):
                self._gallery_thumb_labels = {}
            self._gallery_thumb_labels[file_path] = thumb_label
            
            # Make clickable
            thumb_label.mousePressEvent = lambda e, fp=file_path: self._gallery_item_clicked(fp)
            
            # Create item widget - set fixed height to match row
            item_widget = QWidget()
            item_widget.setFixedHeight(total_row_height)  # CRITICAL: Match row height exactly
            item_widget.setStyleSheet(f"""
                QWidget {{
                    background-color: {theme.VOID};
                    margin: 0px;
                    padding: 0px;
                }}
            """)
            item_layout = QVBoxLayout(item_widget)
            item_layout.setContentsMargins(0, 0, 0, 0)  # No margins
            item_layout.setSpacing(0)  # No spacing
            # CRITICAL: Align label to center to prevent stretching
            item_layout.setAlignment(Qt.AlignmentFlag.AlignCenter)
            
            item_layout.addWidget(thumb_label, alignment=Qt.AlignmentFlag.AlignCenter)
            
            # Load thumbnail asynchronously
            self._load_gallery_thumbnail_async_justified(file_path, thumb_label, new_width, new_height)
            
            row_layout.addWidget(item_widget)
            
            # Add equal spacing after each image (except the last one)
            if i < len(row_items) - 1 and spacing_between > 0:
                spacer = QWidget()
                spacer.setFixedWidth(int(spacing_between))
                spacer.setFixedHeight(total_row_height)  # Match row height
                spacer.setStyleSheet("background-color: transparent; margin: 0px; padding: 0px;")
                row_layout.addWidget(spacer)
        
        # Add row widget with no spacing (vertical spacing is already 0 in gallery_content_layout)
        self.gallery_content_layout.addWidget(row_widget)
        # Store row widget reference
        self._gallery_row_widgets[row_index] = row_widget
        
        # Ensure no additional spacing is added
        self.gallery_content_layout.setSpacing(0)
        self.gallery_content_layout.setContentsMargins(0, 0, 0, 0)
    
    # GALLERY FUNCTIONALITY COMMENTED OUT
    # def _load_gallery_thumbnail_async_justified(self, file_path, thumb_label, target_width, target_height, delay=10):
    #     """Load thumbnail for justified gallery item asynchronously"""
    #     pass  # Gallery functionality disabled
        import time
        import logging
        import os
        from PyQt6.QtCore import QTimer
        logger = logging.getLogger(__name__)
        
        # Validate inputs
        if not file_path or not thumb_label:
            logger.warning(f"[GALLERY] Invalid inputs for thumbnail load: file_path={file_path}, thumb_label={thumb_label}")
            return
        
        # Track loading start time
        if file_path in self._gallery_load_tracking:
            self._gallery_load_tracking[file_path]['start_time'] = time.time()
        else:
            logger.warning(f"[GALLERY] File {os.path.basename(file_path)} not in load tracking")
        
        # Store target dimensions in local variables to ensure they're available in closure
        final_target_width = target_width
        final_target_height = target_height
        
        def load_thumbnail():
            load_start = time.time()
            # Use local variables for target dimensions
            local_target_width = final_target_width
            local_target_height = final_target_height
            
            try:
                logger.debug(f"[GALLERY] Starting load for {os.path.basename(file_path)}")
                # Get or load pixmap
                pixmap = self._get_gallery_pixmap(file_path)
                if not pixmap or pixmap.isNull():
                    # Try to load asynchronously if not in cache
                    logger.debug(f"[GALLERY] Pixmap not in cache for {os.path.basename(file_path)}, loading async")
                    if file_path in self._gallery_load_tracking:
                        self._gallery_load_tracking[file_path]['loaded'] = False
                    # Load pixmap asynchronously - it will update the label when ready
                    self._load_gallery_pixmap_async(file_path)
                    # Return early - label will be updated by _load_gallery_pixmap_async
                    return
                
                # Mark as loaded
                load_time = time.time() - load_start
                if file_path in self._gallery_load_tracking:
                    self._gallery_load_tracking[file_path]['loaded'] = True
                    self._gallery_load_tracking[file_path]['load_time'] = load_time
                logger.info(f"[GALLERY] [PIXMAP] {os.path.basename(file_path)} - Loaded from cache in {load_time:.3f}s")
                
                # Get actual image dimensions
                pixmap_width = pixmap.width()
                pixmap_height = pixmap.height()
                if pixmap_width <= 0 or pixmap_height <= 0:
                    logger.warning(f"[GALLERY] Invalid pixmap size for {os.path.basename(file_path)}: {pixmap_width}x{pixmap_height}")
                    return
                
                # Update aspect cache with actual image dimensions
                actual_aspect = pixmap_width / pixmap_height
                self.gallery_aspect_cache[file_path] = actual_aspect
                
                # Log original image dimensions and aspect ratio
                logger.info(f"[GALLERY] [THUMBNAIL] {os.path.basename(file_path)} - Original: {pixmap_width}x{pixmap_height}, Aspect: {actual_aspect:.3f}")
                
                # For fixed height gallery: scale to fixed height while preserving aspect ratio
                # Reference code: resized = pixmap.scaled(QSize(w, ROW_HEIGHT), Qt.KeepAspectRatio, Qt.SmoothTransformation)
                # We use the target_height as the fixed constraint (this is the row_height from layout)
                target_height = local_target_height if local_target_height > 0 else self.gallery_row_height
                
                # Get label size for logging
                label_width = thumb_label.width()
                label_height = thumb_label.height()
                label_aspect = label_width / label_height if label_height > 0 else 0
                logger.info(f"[GALLERY] [THUMBNAIL] {os.path.basename(file_path)} - Label: {label_width}x{label_height}, Label Aspect: {label_aspect:.3f}")
                
                # Calculate width based on actual image aspect ratio and fixed height
                scaled_width = int(target_height * actual_aspect)
                scaled_height = target_height
                scaled_aspect = scaled_width / scaled_height if scaled_height > 0 else 0
                logger.info(f"[GALLERY] [THUMBNAIL] {os.path.basename(file_path)} - Scaled Target: {scaled_width}x{scaled_height}, Scaled Aspect: {scaled_aspect:.3f}")
                
                # Scale pixmap to fixed height while preserving aspect ratio
                scaled_pixmap = pixmap.scaled(
                    QSize(scaled_width, scaled_height),
                    Qt.AspectRatioMode.KeepAspectRatio,
                    Qt.TransformationMode.SmoothTransformation
                )
                
                if scaled_pixmap.isNull():
                    logger.warning(f"[GALLERY] Failed to scale pixmap for {os.path.basename(file_path)}")
                    return
                
                # Log actual scaled pixmap dimensions
                actual_scaled_width = scaled_pixmap.width()
                actual_scaled_height = scaled_pixmap.height()
                actual_scaled_aspect = actual_scaled_width / actual_scaled_height if actual_scaled_height > 0 else 0
                logger.info(f"[GALLERY] [THUMBNAIL] {os.path.basename(file_path)} - Scaled Result: {actual_scaled_width}x{actual_scaled_height}, Result Aspect: {actual_scaled_aspect:.3f}")
                
                # CRITICAL: Resize label to match scaled pixmap size (like reference code: thumb.setFixedSize(resized.size()))
                # This ensures the label matches the pixmap dimensions exactly, preventing compression
                # The label size must match the pixmap size to avoid stretching/compression
                display_start = time.time()
                thumb_label.setFixedSize(actual_scaled_width, actual_scaled_height)
                thumb_label.setPixmap(scaled_pixmap)
                thumb_label.set_original_pixmap(pixmap)
                
                # Log final state
                final_label_width = thumb_label.width()
                final_label_height = thumb_label.height()
                final_pixmap_width = scaled_pixmap.width()
                final_pixmap_height = scaled_pixmap.height()
                logger.info(f"[GALLERY] [THUMBNAIL] {os.path.basename(file_path)} - Final Label: {final_label_width}x{final_label_height}, Pixmap: {final_pixmap_width}x{final_pixmap_height}")
                display_time = time.time() - display_start
                
                # Mark as displayed
                if file_path in self._gallery_load_tracking:
                    self._gallery_load_tracking[file_path]['displayed'] = True
                    self._gallery_load_tracking[file_path]['display_time'] = display_time
                    total_time = time.time() - self._gallery_load_tracking[file_path]['start_time']
                    logger.info(f"[GALLERY] [IMAGE] {os.path.basename(file_path)} - Loaded in {load_time:.3f}s, Displayed in {display_time:.3f}s, Total: {total_time:.3f}s")
            except Exception as e:
                logger.warning(f"Error loading justified thumbnail for {os.path.basename(file_path)}: {e}")
                import traceback
                logger.debug(f"Traceback: {traceback.format_exc()}")
                if file_path in self._gallery_load_tracking:
                    self._gallery_load_tracking[file_path]['loaded'] = False
                    self._gallery_load_tracking[file_path]['displayed'] = False
        
        # Use a small delay to allow UI to update first
        QTimer.singleShot(10, load_thumbnail)
    
    # GALLERY FUNCTIONALITY COMMENTED OUT
    # def _load_gallery_pixmap_async(self, file_path):
    #     """Load pixmap asynchronously and update specific thumbnail when ready"""
    #     pass  # Gallery functionality disabled
        import time
        import logging
        from PyQt6.QtCore import QTimer
        from PIL import Image
        logger = logging.getLogger(__name__)
        
        # Track loading start time if not already tracked
        if file_path not in self._gallery_load_tracking:
            self._gallery_load_tracking[file_path] = {
                'start_time': time.time(),
                'loaded': False,
                'displayed': False,
                'load_time': None,
                'display_time': None
            }
        elif self._gallery_load_tracking[file_path]['start_time'] is None:
            self._gallery_load_tracking[file_path]['start_time'] = time.time()
        
        def load_pixmap():
            load_start = time.time()
            try:
                # Check if already loaded by another thread/method (avoid duplicate loading)
                if file_path in self.gallery_pixmaps:
                    pixmap = self.gallery_pixmaps[file_path]
                    if pixmap and not pixmap.isNull():
                        # Already loaded, skip reloading but still update label if needed
                        load_time = time.time() - load_start
                        if file_path in self._gallery_load_tracking:
                            if not self._gallery_load_tracking[file_path]['loaded']:
                                self._gallery_load_tracking[file_path]['loaded'] = True
                                self._gallery_load_tracking[file_path]['load_time'] = load_time
                        # Continue to update label below
                        # (label update logic is at the end of this function)
                    else:
                        # Pixmap exists but is null, try to reload
                        pixmap = None
                
                # Try to load from cache or file if not already loaded
                if not pixmap or pixmap.isNull():
                    pixmap = self._get_gallery_pixmap(file_path)
                
                # If not in cache, try to load directly
                
                if not pixmap or pixmap.isNull():
                    if os.path.exists(file_path):
                        file_ext = os.path.splitext(file_path)[1].lower()
                        raw_extensions = ['.arw', '.cr2', '.nef', '.raf', '.orf', '.dng', '.cr3', '.rw2', '.rwl', '.srw']
                        
                        # For RAW files, try to extract embedded JPEG preview (fast)
                        if file_ext in raw_extensions:
                            try:
                                pixmap = self._extract_embedded_preview(file_path)
                                if pixmap and not pixmap.isNull():
                                    logger.debug(f"[GALLERY] Loaded embedded preview for gallery: {os.path.basename(file_path)}")
                            except Exception as raw_error:
                                logger.debug(f"Error extracting embedded preview for {os.path.basename(file_path)}: {raw_error}")
                                pixmap = None
                        
                        # For non-RAW files, try direct QPixmap load
                        if (not pixmap or pixmap.isNull()) and file_ext not in raw_extensions:
                            pixmap = self._load_pixmap_safe(file_path)
                            if pixmap.isNull():
                                # If QPixmap fails, try PIL Image
                                try:
                                    pil_image = Image.open(file_path)
                                    if pil_image.mode != 'RGB':
                                        pil_image = pil_image.convert('RGB')
                                    # Convert PIL Image to QPixmap
                                    width, height = pil_image.size
                                    image_bytes = pil_image.tobytes('raw', 'RGB')
                                    # CRITICAL: Calculate bytes_per_line for PIL Image
                                    bytes_per_line = 3 * width  # RGB = 3 channels
                                    qimage = QImage(image_bytes, width, height, bytes_per_line, QImage.Format.Format_RGB888)
                                    if not qimage.isNull():
                                        pixmap = QPixmap.fromImage(qimage)
                                    else:
                                        pixmap = None
                                except Exception as pil_error:
                                    logger.debug(f"Error loading with PIL for {os.path.basename(file_path)}: {pil_error}")
                                    pixmap = None
                        
                        # If still no pixmap, try to get thumbnail from image cache
                        if (not pixmap or pixmap.isNull()) and hasattr(self, 'image_cache'):
                            try:
                                thumbnail_data = self.image_cache.get_thumbnail(file_path)
                                if thumbnail_data is not None:
                                    # Use unified conversion method
                                    pixmap = self._numpy_to_qpixmap(thumbnail_data)
                            except Exception as thumb_error:
                                logger.debug(f"Error getting thumbnail from cache for {os.path.basename(file_path)}: {thumb_error}")
                                import traceback
                                logger.debug(f"Traceback: {traceback.format_exc()}")
                
                if pixmap and not pixmap.isNull():
                    # Store in gallery cache
                    self.gallery_pixmaps[file_path] = pixmap
                    # Also cache in global image cache for smooth switching between views
                    try:
                        self.image_cache.put_pixmap(file_path, pixmap)
                    except Exception:
                        pass  # Cache might be full, continue anyway
                    # Update aspect cache
                    aspect = pixmap.width() / pixmap.height() if pixmap.height() > 0 else 4.0 / 3.0
                    self.gallery_aspect_cache[file_path] = aspect
                    load_time = time.time() - load_start
                    
                    # Mark as loaded
                    if file_path in self._gallery_load_tracking:
                        self._gallery_load_tracking[file_path]['loaded'] = True
                        self._gallery_load_tracking[file_path]['load_time'] = load_time
                        logger.debug(f"[GALLERY] [PIXMAP] {os.path.basename(file_path)} - Loaded pixmap in {load_time:.3f}s")
                    
                    # Update the specific thumbnail label directly instead of refreshing entire gallery
                    if hasattr(self, '_gallery_thumb_labels') and file_path in self._gallery_thumb_labels:
                        thumb_label = self._gallery_thumb_labels[file_path]
                        if thumb_label:
                            # Get actual image dimensions
                            pixmap_width = pixmap.width()
                            pixmap_height = pixmap.height()
                            if pixmap_width <= 0 or pixmap_height <= 0:
                                return
                            
                            # Update aspect cache with actual image dimensions
                            actual_aspect = pixmap_width / pixmap_height
                            self.gallery_aspect_cache[file_path] = actual_aspect
                            
                            # Log original image dimensions and aspect ratio
                            logger.info(f"[GALLERY] [THUMBNAIL] {os.path.basename(file_path)} - Original: {pixmap_width}x{pixmap_height}, Aspect: {actual_aspect:.3f}")
                            
                            # For fixed height gallery: scale to fixed height while preserving aspect ratio
                            # Reference code: resized = pixmap.scaled(QSize(w, ROW_HEIGHT), Qt.KeepAspectRatio, Qt.SmoothTransformation)
                            # Get label's fixed height (row_height)
                            label_height = thumb_label.height()
                            if label_height <= 0:
                                label_height = self.gallery_row_height
                            
                            label_width = thumb_label.width()
                            label_aspect = label_width / label_height if label_height > 0 else 0
                            logger.info(f"[GALLERY] [THUMBNAIL] {os.path.basename(file_path)} - Label: {label_width}x{label_height}, Label Aspect: {label_aspect:.3f}")
                            
                            # Calculate width based on actual image aspect ratio and fixed height
                            scaled_width = int(label_height * actual_aspect)
                            scaled_height = label_height
                            scaled_aspect = scaled_width / scaled_height if scaled_height > 0 else 0
                            logger.info(f"[GALLERY] [THUMBNAIL] {os.path.basename(file_path)} - Scaled Target: {scaled_width}x{scaled_height}, Scaled Aspect: {scaled_aspect:.3f}")
                            
                            # Scale pixmap to fixed height while preserving aspect ratio
                            scaled_pixmap = pixmap.scaled(
                                QSize(scaled_width, scaled_height),
                                Qt.AspectRatioMode.KeepAspectRatio,
                                Qt.TransformationMode.SmoothTransformation
                            )
                            
                            if scaled_pixmap.isNull():
                                logger.warning(f"[GALLERY] Failed to scale pixmap for {os.path.basename(file_path)}")
                                return
                            
                            # Log actual scaled pixmap dimensions
                            actual_scaled_width = scaled_pixmap.width()
                            actual_scaled_height = scaled_pixmap.height()
                            actual_scaled_aspect = actual_scaled_width / actual_scaled_height if actual_scaled_height > 0 else 0
                            logger.info(f"[GALLERY] [THUMBNAIL] {os.path.basename(file_path)} - Scaled Result: {actual_scaled_width}x{actual_scaled_height}, Result Aspect: {actual_scaled_aspect:.3f}")
                            
                            # CRITICAL: Resize label to match scaled pixmap size (like reference code: thumb.setFixedSize(resized.size()))
                            # This ensures the label matches the pixmap dimensions exactly, preventing compression
                            # The label size must match the pixmap size to avoid stretching/compression
                            display_start = time.time()
                            thumb_label.setFixedSize(actual_scaled_width, actual_scaled_height)
                            thumb_label.setPixmap(scaled_pixmap)
                            thumb_label.set_original_pixmap(pixmap)
                            
                            # Log final state
                            final_label_width = thumb_label.width()
                            final_label_height = thumb_label.height()
                            final_pixmap_width = scaled_pixmap.width()
                            final_pixmap_height = scaled_pixmap.height()
                            logger.info(f"[GALLERY] [THUMBNAIL] {os.path.basename(file_path)} - Final Label: {final_label_width}x{final_label_height}, Pixmap: {final_pixmap_width}x{final_pixmap_height}")
                            display_time = time.time() - display_start
                            
                            # Mark as displayed
                            if file_path in self._gallery_load_tracking:
                                self._gallery_load_tracking[file_path]['displayed'] = True
                                self._gallery_load_tracking[file_path]['display_time'] = display_time
                                total_time = time.time() - self._gallery_load_tracking[file_path]['start_time']
                                logger.debug(f"[GALLERY] [IMAGE] {os.path.basename(file_path)} - Displayed in {display_time:.3f}s, Total: {total_time:.3f}s")
                else:
                    # Failed to load
                    logger.warning(f"[GALLERY] [PIXMAP] Failed to load pixmap for {os.path.basename(file_path)}")
                    if file_path in self._gallery_load_tracking:
                        self._gallery_load_tracking[file_path]['loaded'] = False
                        self._gallery_load_tracking[file_path]['displayed'] = False
            except Exception as e:
                logger.warning(f"Error loading pixmap async for {os.path.basename(file_path)}: {e}")
                import traceback
                logger.debug(f"Traceback: {traceback.format_exc()}")
                if file_path in self._gallery_load_tracking:
                    self._gallery_load_tracking[file_path]['loaded'] = False
                    self._gallery_load_tracking[file_path]['displayed'] = False
        
        QTimer.singleShot(50, load_pixmap)
    
