    @staticmethod
    def _gallery_event_modifiers(event=None):
        """Reliable modifier read for gallery clicks (macOS press events often omit Cmd)."""
        from PyQt6.QtWidgets import QApplication

        mods = Qt.KeyboardModifier.NoModifier
        if event is not None:
            mods |= event.modifiers()
        mods |= QApplication.keyboardModifiers()
        return mods

    @staticmethod
    def _gallery_has_extend_modifier(modifiers) -> bool:
        """Ctrl (Windows/Linux) or Cmd (macOS) for gallery extend-selection."""
        return bool(
            modifiers
            & (Qt.KeyboardModifier.ControlModifier | Qt.KeyboardModifier.MetaModifier)
        )

    @staticmethod
    def _gallery_has_shift_modifier(modifiers) -> bool:
        return bool(modifiers & Qt.KeyboardModifier.ShiftModifier)

    def _gallery_refresh_selection_ui(self) -> None:
        gj = getattr(self, "gallery_justified", None)
        if gj is not None and hasattr(gj, "refresh_gallery_selection_visuals"):
            gj.refresh_gallery_selection_visuals()
        self._sync_gallery_selection_chrome()
        self._sync_share_button_visibility()
        self._sync_compare_button_visibility()

    def _gallery_set_selection_keys(self, keys: set) -> None:
        self._gallery_selected_paths = set(keys)
        self._gallery_refresh_selection_ui()

    def _gallery_selection_ordered_paths(self) -> List[str]:
        """Ordered paths used for Shift+click range selection (matches on-screen gallery)."""
        if getattr(self, "view_mode", "") == "gallery":
            gj = getattr(self, "gallery_justified", None)
            if gj is not None:
                visible = list(getattr(gj, "images", []) or [])
                if visible:
                    return visible
            return self._gallery_files_for_display()
        return list(getattr(self, "image_files", []) or [])

    def _gallery_shift_click_selection(self, file_path: str) -> None:
        """Shift+click range selection.

        A Shift+click only extends an inclusive range when the previous action was
        also a Shift+click. The first Shift+click after a Cmd/Ctrl+click (or any
        non-shift action) just sets a fresh range anchor and selects that one tile,
        so picking 4th→6th after Cmd+click 2nd won't pull in the 3rd.
        """
        canonical = self._gallery_canonical_path(file_path)
        if not canonical:
            return
        key = _norm_path(canonical)
        paths = self._gallery_selection_ordered_paths()
        norm_list = [_norm_path(p) for p in paths if p]
        if key not in norm_list:
            return
        selected = set(getattr(self, "_gallery_selected_paths", set()) or set())
        anchor = getattr(self, "_gallery_selection_anchor", None)
        last_action = getattr(self, "_gallery_last_select_action", None)
        if last_action != "shift" or not anchor or anchor not in norm_list:
            self._gallery_selection_anchor = key
            self._gallery_last_select_action = "shift"
            selected.add(key)
            self._gallery_set_selection_keys(selected)
            return
        try:
            i0 = norm_list.index(anchor)
            i1 = norm_list.index(key)
        except ValueError:
            self._gallery_selection_anchor = key
            self._gallery_last_select_action = "shift"
            selected.add(key)
            self._gallery_set_selection_keys(selected)
            return
        lo, hi = (i0, i1) if i0 <= i1 else (i1, i0)
        selected |= {norm_list[i] for i in range(lo, hi + 1)}
        self._gallery_last_select_action = "shift"
        self._gallery_set_selection_keys(selected)

    def _gallery_canonical_path(self, file_path: str) -> Optional[str]:
        if not file_path or not self.image_files:
            return None
        target = _norm_path(file_path)
        for p in self.image_files:
            if _norm_path(p) == target:
                return p
        return None

    def _is_gallery_path_selected(self, file_path: str) -> bool:
        raw = set(getattr(self, "_gallery_selected_paths", set()) or set())
        if not raw:
            return False
        key = _norm_path(file_path)
        if key in raw:
            return True
        member_keys = self._gallery_selection_keys_for_tile(file_path)
        if len(member_keys) > 1:
            return member_keys <= raw
        return False

    def _gallery_has_selection(self) -> bool:
        return bool(getattr(self, "_gallery_selected_paths", None))

    def _clear_gallery_selection(self) -> None:
        selected = getattr(self, "_gallery_selected_paths", None)
        if selected:
            selected.clear()
        self._gallery_selection_anchor = None
        self._gallery_last_select_action = None
        self._gallery_refresh_selection_ui()

    def _request_clear_gallery_selection(self) -> None:
        self._clear_gallery_selection()

    def _load_gallery_pixmap_async(self, file_path: str) -> None:
        """Legacy justified-gallery async loader (no-op; external gallery handles loads)."""
        return

    @staticmethod
    def _share_button_platform_enabled() -> bool:
        """Bottom action opens selected image(s) in another app on desktop platforms."""
        return sys.platform in ("darwin", "win32")

    def _sync_gallery_selection_chrome(self) -> None:
        """Status text when multi-select is active."""
        n = len(self._gallery_selected_expanded_norm_keys())
        if n <= 0:
            return
        if hasattr(self, "status_bar") and self.status_bar:
            vm = getattr(self, "view_mode", "single")
            if vm == "gallery":
                if getattr(self, "_burst_group_view_active", False):
                    if self._burst_group_compare_plan() is not None:
                        hint = (
                            "Compare burst group (C) · Rate 0–5 · "
                            "Share; Ctrl/Cmd+click or Shift+click to select"
                        )
                    else:
                        hint = "Share · Rate 0–5; Ctrl/Cmd+click or Shift+click to select"
                else:
                    from comparison_mode import CompareEntry

                    plan = self._compare_session_plan()
                    if plan is not None and plan[1] == CompareEntry.BURST_GROUP:
                        hint = "Compare burst group (C) · Share · Delete/Down"
                    else:
                        hint = "Compare selection (C) · Share · Delete/Down"
            else:
                hint = "Share — open in editor, Delete/Down bulk actions"
            self.status_bar.showMessage(
                f"{n} image{'s' if n != 1 else ''} selected — {hint}",
                5000,
            )

    def _gallery_has_bookmarks(self) -> bool:
        return bool(getattr(self, "_gallery_bookmarked_paths", None))

    def _is_gallery_path_bookmarked(self, file_path: str) -> bool:
        return _norm_path(file_path) in getattr(self, "_gallery_bookmarked_paths", set())

    def _gallery_toggle_path_bookmark(self, file_path: str) -> None:
        canonical = self._gallery_canonical_path(file_path)
        if not canonical:
            return
        key = _norm_path(canonical)
        bookmarked = getattr(self, "_gallery_bookmarked_paths", set())
        if key in bookmarked:
            bookmarked.discard(key)
            msg = "Bookmark removed"
        else:
            bookmarked.add(key)
            msg = "Bookmarked for opening in another app"
        self._gallery_bookmarked_paths = bookmarked
        self._apply_gallery_bookmark_visual_updates()
        if hasattr(self, "status_bar") and self.status_bar:
            self.status_bar.showMessage(msg, 2000)

    def _apply_gallery_bookmark_visual_updates(self) -> None:
        self._refresh_filmstrip_bookmark_visuals()
        self._refresh_gallery_bookmark_visuals()
        self._sync_bookmark_indicator()
        cleared_empty_filter = self._maybe_clear_empty_bookmark_filter()
        if (
            getattr(self, "view_mode", "") == "gallery"
            and getattr(self, "_gallery_bookmark_filter_active", False)
        ):
            self._apply_gallery_bookmark_filter()
        elif getattr(self, "view_mode", "") == "gallery":
            self._sync_share_button_visibility()
            if cleared_empty_filter:
                self._apply_gallery_bookmark_filter()
        if getattr(self, "view_mode", "single") == "single" and getattr(
            self, "_gallery_bookmark_filter_active", False
        ):
            self._sync_filmstrip_to_folder()
        self._save_persisted_gallery_bookmarks()

    def _gallery_toggle_selected_bookmarks(self) -> None:
        """Toggle bookmark state for each selected gallery image."""
        paths = self._gallery_selected_canonical_paths()
        if not paths:
            return
        bookmarked = getattr(self, "_gallery_bookmarked_paths", set())
        added = 0
        removed = 0
        for p in paths:
            canonical = self._gallery_canonical_path(p)
            if not canonical:
                continue
            key = _norm_path(canonical)
            if key in bookmarked:
                bookmarked.discard(key)
                removed += 1
            else:
                bookmarked.add(key)
                added += 1
        self._gallery_bookmarked_paths = bookmarked
        self._apply_gallery_bookmark_visual_updates()
        if hasattr(self, "status_bar") and self.status_bar:
            if added and not removed:
                msg = f"Bookmarked {added} image{'s' if added != 1 else ''}"
            elif removed and not added:
                msg = f"Removed bookmark from {removed} image{'s' if removed != 1 else ''}"
            else:
                msg = (
                    f"Updated bookmarks ({added} added, {removed} removed)"
                    if added or removed
                    else "No bookmarks changed"
                )
            self.status_bar.showMessage(msg, 2500)

    def _gallery_bookmarked_canonical_paths(self) -> List[str]:
        return self._filter_paths_to_bookmarked(list(getattr(self, "image_files", []) or []))

    def _gallery_files_for_display(self) -> List[str]:
        """Gallery file list, optionally narrowed to bookmarked images only."""
        if getattr(self, "view_mode", "") != "gallery":
            return list(getattr(self, "image_files", []) or [])
        return self._gallery_effective_files()

    def _should_show_slideshow_button(self) -> bool:
        if getattr(self, "_burst_group_view_active", False):
            return False
        if not getattr(self, "image_files", None):
            return False
        if self._adjust_panel_active():
            return False
        if getattr(self, "view_mode", "single") == "single":
            return True
        return getattr(self, "view_mode", "") == "gallery"

    def _sync_slideshow_button_visibility(self) -> None:
        btn = getattr(self, "slideshow_bottom_button", None)
        if btn is None:
            return
        vis = self._should_show_slideshow_button()
        if btn.isVisible() != vis:
            btn.setVisible(vis)

    def _gallery_viewport_scroll_path(self) -> str | None:
        """Resolve the path shown in the gallery grid for scroll-to-current."""
        path = (
            getattr(self, "current_file_path", None)
            or getattr(self, "_gallery_scroll_target_path", None)
        )
        if not path:
            return None
        gj = getattr(self, "gallery_justified", None)
        if gj is None or not hasattr(gj, "_resolve_gallery_path"):
            return path
        resolved = gj._resolve_gallery_path(path)
        if resolved:
            return resolved
        norm = _norm_path(path)
        path_to_group = getattr(self, "_burst_path_to_group", {}) or {}
        for group_id, members in path_to_group.items():
            if not any(_norm_path(m) == norm for m in members):
                continue
            covers = dict(getattr(self, "_burst_group_covers", {}) or {})
            covers.update(getattr(self, "_burst_stack_covers", {}) or {})
            cover = covers.get(group_id) or (members[0] if members else None)
            if cover:
                resolved = gj._resolve_gallery_path(cover)
                if resolved:
                    return resolved
            for member in members:
                resolved = gj._resolve_gallery_path(member)
                if resolved:
                    return resolved
            break
        return path

    def _scroll_gallery_to_current_file(self, *, backup: bool = True) -> None:
        """Scroll the gallery so the current single-view file is in the viewport."""
        from PyQt6.QtCore import QTimer

        gj = getattr(self, "gallery_justified", None)
        if gj is None or not hasattr(gj, "scroll_to_file"):
            return
        anchor = self._gallery_viewport_scroll_path()
        if not anchor:
            return
        gj.scroll_to_file(anchor)
        if backup:
            QTimer.singleShot(300, lambda p=anchor: gj.scroll_to_file(p))
            QTimer.singleShot(650, lambda p=anchor: gj.scroll_to_file(p))

    def _maybe_clear_empty_bookmark_filter(self) -> bool:
        """Leave bookmark-only view when the folder has no bookmarks left."""
        if not getattr(self, "_gallery_bookmark_filter_active", False):
            return False
        if getattr(self, "_gallery_bookmarked_paths", set()):
            return False
        self._gallery_bookmark_filter_active = False
        self._sync_bookmark_indicator()
        return True

    def _maybe_clear_empty_rating_filter(self) -> bool:
        """Reset the rating filter when no images meet the threshold anymore."""
        min_rating = int(getattr(self, "_gallery_rating_filter_min", 0) or 0)
        if min_rating <= 0:
            return False
        files = list(getattr(self, "image_files", []) or [])
        if any(self._gallery_path_rating(p) >= min_rating for p in files):
            return False
        # Memory-only ratings: while bulk metadata is still loading (or empty),
        # do not clear — SQLite-only ratings land with the folder meta fetch.
        if getattr(self, "_gallery_metadata_fetch_in_progress", False):
            return False
        if not (getattr(self, "_gallery_bulk_metadata", None) or {}):
            return False
        self._gallery_rating_filter_min = 0
        self._sync_gallery_rating_filter_stars()
        return True

    def _clear_gallery_rating_filter(self) -> bool:
        """Clear the gallery rating filter; keep active search/bookmark filters if any."""
        if getattr(self, "view_mode", "") != "gallery":
            return False
        if int(getattr(self, "_gallery_rating_filter_min", 0) or 0) <= 0:
            return False
        self._gallery_rating_filter_min = 0
        self._sync_gallery_rating_filter_stars()
        self._apply_gallery_bookmark_filter()
        return True

    def _on_gallery_rating_star_clicked(self, n: int) -> None:
        if getattr(self, "view_mode", "") != "gallery":
            return
        current = int(getattr(self, "_gallery_rating_filter_min", 0) or 0)
        self._gallery_rating_filter_min = 0 if current == n else n
        self._sync_gallery_rating_filter_stars()
        self._apply_gallery_bookmark_filter()

    def _sync_gallery_rating_filter_stars(self) -> None:
        widget = getattr(self, "gallery_rating_filter_stars", None)
        if widget is None:
            return
        in_gallery = getattr(self, "view_mode", "") == "gallery"
        files = list(getattr(self, "image_files", None) or [])
        min_rating = int(getattr(self, "_gallery_rating_filter_min", 0) or 0)
        # Hide the star row entirely when nothing in the current gallery has
        # ever been rated -- clicking a star then would just narrow to zero
        # results (or immediately self-clear via _maybe_clear_empty_rating_
        # filter), a non-functional control with no visible feedback. Keep it
        # visible while a filter is already active (min_rating > 0) even if
        # this particular sync call races ahead of _maybe_clear_empty_rating_
        # filter -- that function is what actually resets the filter once it
        # observes zero qualifying images, and the star row must stay up
        # until then so the active-filter state stays visible/clearable.
        if not in_gallery or not files:
            widget.hide()
            return
        # Gallery-only: still O(n) over paths, but ratings are memory-only
        # (bulk meta / RAM EXIF) — never per-file get_exif() disk/SQLite.
        any_rated = min_rating > 0 or self._gallery_folder_has_any_rating(files)
        if not any_rated:
            widget.hide()
            return
        widget.show()
        buttons = getattr(self, "_gallery_rating_filter_buttons", None) or []
        filled = getattr(self, "_rating_star_filled_icon", None)
        empty = getattr(self, "_rating_star_empty_icon", None)
        for i, btn in enumerate(buttons, start=1):
            btn.setIcon((filled if i <= min_rating else empty) or QIcon())
            btn.setToolTip(
                f"Show {i}★ and above (click again to clear)"
                if i != min_rating
                else "Click to clear rating filter"
            )

    def _on_gallery_clear_filter_clicked(self) -> None:
        self._clear_gallery_bookmark_filter()
        self._clear_gallery_rating_filter()

    def _sync_gallery_clear_filter_button(self) -> None:
        btn = getattr(self, "gallery_clear_filter_button", None)
        if btn is None:
            return
        in_gallery = getattr(self, "view_mode", "") == "gallery"
        filter_active = bool(
            getattr(self, "_gallery_bookmark_filter_active", False)
        ) or int(getattr(self, "_gallery_rating_filter_min", 0) or 0) > 0
        btn.setVisible(in_gallery and filter_active)

    def _clear_gallery_bookmark_filter(self) -> bool:
        """Leave bookmark-only gallery view; keep active search results if any."""
        if getattr(self, "view_mode", "") != "gallery":
            return False
        if not getattr(self, "_gallery_bookmark_filter_active", False):
            return False
        self._gallery_bookmark_filter_active = False
        self._sync_bookmark_indicator()
        self._apply_gallery_bookmark_filter()
        return True

    def _on_bookmark_slot_clicked(self) -> None:
        """Legacy bookmark chrome — filter/toggle UI is retired in favor of ratings."""
        vm = getattr(self, "view_mode", "")
        if vm == "single":
            if hasattr(self, "status_bar") and self.status_bar is not None:
                self.status_bar.showMessage(
                    "Rate with 1–5 (0 clears). Bookmarks are no longer used for culling.",
                    3500,
                )
            return
        if vm != "gallery":
            return
        # Clear any leftover bookmark filter from older sessions; rating filter
        # is the supported way to narrow the gallery now.
        if getattr(self, "_gallery_bookmark_filter_active", False):
            self._clear_gallery_bookmark_filter()
            return
        if hasattr(self, "status_bar") and self.status_bar is not None:
            self.status_bar.showMessage(
                "Use the bottom stars to filter by rating (bookmarks retired).",
                3500,
            )

    def _gallery_scope_filter_qualifier(self) -> str:
        """Short qualifier for the active bookmark/rating gallery filter(s), e.g. 'bookmarked, 3★+'."""
        bookmark_active = bool(getattr(self, "_gallery_bookmark_filter_active", False))
        min_rating = int(getattr(self, "_gallery_rating_filter_min", 0) or 0)
        parts = []
        if bookmark_active:
            parts.append("bookmarked")
        if min_rating > 0:
            parts.append(f"{min_rating}★+")
        return ", ".join(parts)

    def _gallery_scope_filter_description(self) -> str:
        """Human-readable 'images' phrase for the active bookmark/rating gallery filter(s)."""
        qualifier = self._gallery_scope_filter_qualifier()
        return f"{qualifier} images" if qualifier else "images"

    def _apply_gallery_bookmark_filter(self) -> None:
        if getattr(self, "view_mode", "") != "gallery":
            return
        self._maybe_clear_empty_bookmark_filter()
        self._maybe_clear_empty_rating_filter()
        self._sync_gallery_rating_filter_stars()
        self._sync_gallery_clear_filter_button()
        filter_active = bool(
            getattr(self, "_gallery_bookmark_filter_active", False)
        ) or int(getattr(self, "_gallery_rating_filter_min", 0) or 0) > 0
        display_files = self._gallery_files_for_display()
        display_keys = {_norm_path(p) for p in display_files}
        selected = set(getattr(self, "_gallery_selected_paths", set()) or set())
        if selected - display_keys:
            self._gallery_selected_paths = selected & display_keys
            self._gallery_refresh_selection_ui()
        gj = getattr(self, "gallery_justified", None)
        if gj is not None:
            meta = getattr(self, "_gallery_bulk_metadata", None) or {}
            if filter_active:
                if not display_files:
                    scope_desc = self._gallery_scope_filter_description()
                    empty_msg = (
                        f"No matching {scope_desc}"
                        if self._is_semantic_search_filter_active()
                        else f"No {scope_desc}"
                    )
                    gj.set_images([], meta if meta else None)
                    gj.show_empty_message(empty_msg)
                else:
                    if hasattr(gj, "hide_empty_message"):
                        gj.hide_empty_message()
                    gj.set_images(display_files, meta if meta else None)
            else:
                if hasattr(gj, "hide_empty_message"):
                    gj.hide_empty_message()
                anchor = None
                if hasattr(gj, "get_scroll_anchor_path"):
                    try:
                        anchor = gj.get_scroll_anchor_path()
                    except Exception:
                        anchor = None
                display_files = list(getattr(self, "image_files", []) or [])
                if not display_files:
                    gj.set_images([], meta if meta else None)
                    empty_msg = (
                        "No matching images"
                        if self._is_semantic_search_filter_active()
                        else "No images"
                    )
                    gj.show_empty_message(empty_msg)
                else:
                    self._sync_gallery_to_folder_files(
                        meta if meta else None,
                        scroll_anchor_path=anchor,
                        force=True,
                    )
        self._sync_gallery_scrollbar_policy()
        self._update_gallery_counter()
        self._sync_share_button_visibility()
        self._sync_slideshow_button_visibility()
        if hasattr(self, "status_bar") and self.status_bar:
            if filter_active:
                n = len(display_files)
                scope_desc = self._gallery_scope_filter_description()
                if self._is_semantic_search_filter_active():
                    self.status_bar.showMessage(
                        f"Showing {n} matching {scope_desc}",
                        2500,
                    )
                else:
                    self.status_bar.showMessage(
                        f"Showing {n} {scope_desc}",
                        2500,
                    )
            elif self._is_semantic_search_filter_active():
                n = len(getattr(self, "image_files", []) or [])
                self.status_bar.showMessage(
                    f"Showing {n} search result{'s' if n != 1 else ''}",
                    2500,
                )
            else:
                self.status_bar.showMessage("Showing all images", 2000)

    def _sync_single_view_rating_stars(self) -> None:
        widget = getattr(self, "single_view_rating_stars", None)
        if widget is None:
            return
        in_single = getattr(self, "view_mode", "single") == "single"
        has_files = bool(getattr(self, "image_files", None))
        if not in_single or not has_files:
            widget.hide()
            return
        widget.show()
        path = getattr(self, "current_file_path", None)
        rating = self._gallery_path_rating(path) if path else 0
        self._set_rating_stars_display(rating)

    def _set_rating_stars_display(self, rating: int) -> None:
        buttons = getattr(self, "_rating_star_buttons", None)
        if not buttons:
            return
        r = max(0, min(5, int(rating or 0)))
        filled = getattr(self, "_rating_star_filled_icon", None)
        empty = getattr(self, "_rating_star_empty_icon", None)
        for i, btn in enumerate(buttons, start=1):
            btn.setIcon((filled if i <= r else empty) or QIcon())

    def _on_rating_star_clicked(self, n: int) -> None:
        path = getattr(self, "current_file_path", None)
        if not path:
            return
        current = self._gallery_path_rating(path)
        self.rate_current_image(0 if current == n else n)

    def _sync_bookmark_indicator(self) -> None:
        self._sync_single_view_rating_stars()
        self._sync_gallery_rating_filter_stars()
        self._sync_gallery_clear_filter_button()
        # The gallery bookmark-filter star is retired: the rating filter
        # covers "narrow down the gallery". ↑ scrolls the gallery (or
        # promotes in Compare); it no longer toggles bookmarks.
        btn = getattr(self, "batch_mark_indicator", None)
        if btn is not None:
            btn.hide()

    def _refresh_filmstrip_bookmark_visuals(self) -> None:
        bar = self._filmstrip_bar()
        if bar is not None and hasattr(bar, "set_bookmarked_norm_paths"):
            bar.set_bookmarked_norm_paths(
                getattr(self, "_gallery_bookmarked_paths", set()) or set()
            )
        self._sync_bookmark_indicator()

    def _refresh_gallery_bookmark_visuals(self) -> None:
        gj = getattr(self, "gallery_justified", None)
        if gj is not None and hasattr(gj, "refresh_gallery_bookmark_visuals"):
            gj.refresh_gallery_bookmark_visuals()
        if gj is not None and hasattr(gj, "refresh_gallery_burst_visuals"):
            gj.refresh_gallery_burst_visuals()
        if gj is not None and hasattr(gj, "refresh_gallery_edited_visuals"):
            gj.refresh_gallery_edited_visuals()

    def _is_gallery_path_edited(self, file_path: str) -> bool:
        """Cheap "has saved RAW adjustments" signal for the gallery badge.

        RAW-only: sidecars resolve by basename, so a JPEG next to an edited
        RAW of the same name would otherwise be badged (and, since edited
        previews landed, rendered) with the RAW's edits.

        Presence of an ``.xmp`` alone is not enough — rating-only sidecars
        (or foreign LR fields with all our sliders at default) must not
        light the pencil badge after Reset.

        Memoized by sidecar mtime so ``load_visible_images`` does not re-parse
        XML for every tile on every pass (that stalled large-folder gallery
        re-entry).
        """
        from raw_adjustments import editing_features_enabled

        if not editing_features_enabled():
            return False
        if not file_path:
            return False
        try:
            from common_image_loader import is_raw_file
            from raw_adjustments import (
                is_default_adjustments,
                load_adjustments_from_xmp,
                resolve_xmp_path,
            )

            if not is_raw_file(file_path):
                return False
            memo = getattr(self, "_gallery_edited_memo", None)
            if memo is None:
                self._gallery_edited_memo = {}
                memo = self._gallery_edited_memo
            # TTL short-circuit BEFORE any disk stat: load_visible_images calls
            # this per tile per pass, and even the isfile+getmtime pair costs
            # 1-3ms on external volumes — enough to eat the pass budget and
            # starve tile fill after a section jump. External sidecar changes
            # surface within the TTL; in-app edits invalidate the memo directly.
            now = time.time()
            hit = memo.get(file_path)
            if hit is not None and len(hit) >= 3 and (now - hit[2]) < 2.0:
                return bool(hit[1])
            xmp_path = resolve_xmp_path(file_path)
            if not xmp_path or not os.path.isfile(xmp_path):
                memo[file_path] = (None, False, now)
                return False
            try:
                mtime = os.path.getmtime(xmp_path)
            except OSError:
                memo[file_path] = (None, False, now)
                return False
            if hit is not None and hit[0] == mtime:
                memo[file_path] = (mtime, hit[1], now)
                return bool(hit[1])
            edited = not is_default_adjustments(load_adjustments_from_xmp(xmp_path))
            memo[file_path] = (mtime, edited, now)
            return edited
        except Exception:
            return False

    def _invalidate_gallery_edited_memo(self, file_path: str | None = None) -> None:
        """Drop cached edited-badge answers after save/reset."""
        memo = getattr(self, "_gallery_edited_memo", None)
        if not memo:
            return
        if not file_path:
            memo.clear()
            return
        memo.pop(file_path, None)
        try:
            memo.pop(os.path.normpath(file_path), None)
        except Exception:
            pass

    def _bump_gallery_rating_presence_epoch(self) -> None:
        """Invalidate cached 'any file rated?' answers for the star-filter row."""
        self._gallery_rating_presence_epoch = (
            int(getattr(self, "_gallery_rating_presence_epoch", 0) or 0) + 1
        )
        self._gallery_any_rated_cache = None

    def _gallery_path_rating(self, file_path: str) -> int:
        """0-5 star rating for gallery/filmstrip badges and rating filters.

        Memory-only: bulk metadata (folder scan / rate_current_image) then the
        in-RAM EXIF map. Never calls ``get_exif()`` — that path stats + hits
        SQLite per file, and walking thousands of paths from status-bar /
        filter sync on a USB gallery froze the UI for 10s+. Ratings that only
        live in SQLite appear once bulk metadata (or a rate action) lands.
        """
        if not file_path:
            return 0
        meta = getattr(self, "_gallery_bulk_metadata", None) or {}
        row = meta.get(file_path)
        if row and row.get("rating"):
            try:
                return max(0, min(5, int(row["rating"])))
            except (TypeError, ValueError):
                pass
        try:
            cache = getattr(self, "image_cache", None)
            exif = (
                cache.get_exif_memory_only(file_path)
                if cache is not None and hasattr(cache, "get_exif_memory_only")
                else None
            )
        except Exception:
            exif = None
        if exif and exif.get("rating"):
            try:
                return max(0, min(5, int(exif["rating"])))
            except (TypeError, ValueError):
                pass
        return 0

    def _gallery_folder_has_any_rating(self, files) -> bool:
        """True if any path in ``files`` has a known in-memory rating > 0."""
        files = list(files or [])
        epoch = int(getattr(self, "_gallery_rating_presence_epoch", 0) or 0)
        bulk = getattr(self, "_gallery_bulk_metadata", None) or {}
        key = (
            getattr(self, "current_folder", None),
            len(files),
            epoch,
            id(bulk),
            len(bulk),
        )
        cached = getattr(self, "_gallery_any_rated_cache", None)
        if cached is not None and cached[0] == key:
            return bool(cached[1])
        any_rated = False
        for path in files:
            if path and self._gallery_path_rating(path) > 0:
                any_rated = True
                break
        self._gallery_any_rated_cache = (key, any_rated)
        return any_rated

    def _sync_share_button_visibility(self) -> None:
        btn = getattr(self, "share_bottom_button", None)
        if btn is None:
            return
        if not self._share_button_platform_enabled():
            btn.hide()
            return
        if getattr(self, "view_mode", "single") == "compare":
            btn.hide()
            return
        if self._adjust_panel_active():
            btn.hide()
            return
        vis = bool(self._gallery_share_target_paths())
        if getattr(self, "view_mode", "single") == "single" and not getattr(
            self, "image_files", None
        ):
            vis = False
        if btn.isVisible() != vis:
            btn.setVisible(vis)

    def _gallery_share_target_paths(self) -> List[str]:
        """Paths to open/share: gallery multi-select, else all visible bookmarked when filter on; single view uses current file."""
        vm = getattr(self, "view_mode", "")
        if vm == "gallery":
            if self._gallery_has_selection():
                paths = self._gallery_selected_canonical_paths()
            elif getattr(self, "_gallery_bookmark_filter_active", False):
                paths = self._gallery_files_for_display()
            else:
                paths = []
        else:
            p = getattr(self, "current_file_path", None)
            paths = [p] if p else []
        return [
            os.path.abspath(p)
            for p in paths
            if p and os.path.isfile(p)
        ]

    def _gallery_toggle_path_selection(self, file_path: str) -> None:
        canonical = self._gallery_canonical_path(file_path)
        if not canonical:
            return
        storage_key = _norm_path(canonical)
        member_keys = self._gallery_selection_keys_for_tile(file_path)
        selected = set(getattr(self, "_gallery_selected_paths", set()) or set())
        is_stack = len(member_keys) > 1
        if is_stack:
            is_on = storage_key in selected or member_keys <= selected
            if is_on:
                selected.discard(storage_key)
                selected -= member_keys
            else:
                selected.add(storage_key)
                selected |= member_keys
        elif storage_key in selected:
            selected.discard(storage_key)
        else:
            selected.add(storage_key)
        self._gallery_selection_anchor = storage_key
        self._gallery_last_select_action = "toggle"
        self._gallery_set_selection_keys(selected)

    def _gallery_selected_canonical_paths(self) -> List[str]:
        keys = self._gallery_selected_expanded_norm_keys()
        return self._gallery_selected_canonical_paths_from_keys(keys)

    def _confirm_bulk_deletion(self, count: int, *, discard: bool) -> bool:
        if count <= 0:
            return False
        if discard:
            title = "Confirm Move to Discard"
            verb = "move"
            detail = "They will be moved to a Discard folder next to the originals."
        else:
            title = "Confirm Delete"
            verb = "delete"
            detail = "They will be moved to the Recycle Bin."
        noun = "file" if count == 1 else "files"
        dialog = CustomConfirmDialog(
            parent=self,
            title=title,
            message=f"Are you sure you want to {verb} {count} {noun}?",
            informative_text=detail,
            confirm_action="Discard" if discard else "Delete",
        )
        self._is_delete_dialog_open = True
        try:
            dialog.exec()
            return dialog.result_value
        finally:
            self._is_delete_dialog_open = False

    def _remove_files_from_active_image_list(self, file_paths: List[str]) -> None:
        if not file_paths or not self.image_files:
            return
        remove_keys = {_norm_path(p) for p in file_paths if p}
        if not remove_keys:
            return
        self.image_files = [
            p for p in self.image_files if _norm_path(p) not in remove_keys
        ]
        bookmarked = getattr(self, "_gallery_bookmarked_paths", None)
        if bookmarked:
            bookmarked -= remove_keys
            self._gallery_bookmarked_paths = bookmarked
        selected = getattr(self, "_gallery_selected_paths", None)
        if selected:
            selected -= remove_keys
        if self.current_file_path and _norm_path(self.current_file_path) in remove_keys:
            if self.image_files:
                self.current_file_index = min(
                    self.current_file_index, len(self.image_files) - 1
                )
                if self.current_file_index < 0:
                    self.current_file_index = 0
                self.current_file_path = self.image_files[self.current_file_index]
            else:
                self.current_file_index = -1
                self.current_file_path = None

    def _surviving_anchor_after_removal(self, removed_paths) -> Optional[str]:
        """Nearest file that will still exist after removing *removed_paths*.

        The scroll anchor passed to _sync_gallery_to_folder_files must be a
        surviving file: anchoring on a deleted path can never resolve, the
        scroll-to-file retries exhaust, and the gallery lands at the top.
        Prefers the first file after the earliest removed one (reading order),
        falling back to the nearest one before it.
        """
        removed = {os.path.normpath(p) for p in removed_paths if p}
        files = list(getattr(self, "image_files", None) or [])
        first = None
        for i, f in enumerate(files):
            if os.path.normpath(f) in removed:
                first = i
                break
        if first is None:
            return None
        for f in files[first:]:
            if os.path.normpath(f) not in removed:
                return f
        for f in reversed(files[:first]):
            if os.path.normpath(f) not in removed:
                return f
        return None

    def _after_gallery_bulk_file_removal(self, anchor_path: Optional[str] = None) -> None:
        self._clear_gallery_selection()
        self._refresh_filmstrip_bookmark_visuals()
        self._refresh_gallery_bookmark_visuals()
        self._sync_share_button_visibility()
        self._save_persisted_gallery_bookmarks()
        if not self.image_files:
            had_semantic_scope = bool(
                self._semantic_search_backup_files or self._semantic_search_corpus_files
            )
            if had_semantic_scope:
                self._clear_semantic_search_results(silent=True, exit_to_gallery=True)
                inp = getattr(self, "gallery_search_input", None)
                if inp is not None:
                    inp.blockSignals(True)
                    try:
                        inp.clear()
                    finally:
                        inp.blockSignals(False)
            gj = getattr(self, "gallery_justified", None)
            if gj is not None:
                gj.set_images([])
                gj.show_empty_message("No images remaining in this folder")
            self.status_bar.showMessage("No images remaining in folder")
            return
        self._sync_gallery_to_folder_files(
            scroll_anchor_path=anchor_path,
            force=True,
        )
        gj = getattr(self, "gallery_justified", None)
        if gj is not None and hasattr(gj, "refresh_gallery_selection_visuals"):
            gj.refresh_gallery_selection_visuals()

    def delete_gallery_selection(self) -> None:
        paths = self._gallery_selected_canonical_paths()
        if not paths:
            self.status_bar.showMessage("No images selected in gallery", 2500)
            return
        self._stop_slideshow()
        if not self._confirm_bulk_deletion(len(paths), discard=False):
            return
        anchor = self._surviving_anchor_after_removal(paths)
        from send2trash import send2trash

        from image_cache import get_image_cache

        cache = get_image_cache()
        removed = 0
        errors = 0
        for file_path in list(paths):
            if not os.path.exists(file_path):
                self._remove_files_from_active_image_list([file_path])
                self._drop_discarded_from_semantic_corpus(file_path)
                removed += 1
                continue
            try:
                self._cancel_load_and_preload_for_path(file_path)
                cache.invalidate_file(file_path)
                send2trash(os.path.normpath(file_path))
                self._drop_discarded_from_semantic_corpus(file_path)
                self._remove_files_from_active_image_list([file_path])
                removed += 1
            except Exception:
                errors += 1
        if removed:
            self.status_bar.showMessage(
                f"Deleted {removed} image{'s' if removed != 1 else ''}"
                + (f" ({errors} failed)" if errors else ""),
            )
            self._after_gallery_bulk_file_removal(anchor_path=anchor)
            self.schedule_save_session_state()

    def discard_gallery_selection(self) -> None:
        paths = self._gallery_selected_canonical_paths()
        if not paths:
            self.status_bar.showMessage("No images selected in gallery", 2500)
            return
        self._stop_slideshow()
        if not self._confirm_bulk_deletion(len(paths), discard=True):
            return
        from image_cache import get_image_cache

        cache = get_image_cache()
        anchor = self._surviving_anchor_after_removal(paths)
        moved = 0
        errors = 0
        for file_path in list(paths):
            if not os.path.exists(file_path):
                self._remove_files_from_active_image_list([file_path])
                self._drop_discarded_from_semantic_corpus(file_path)
                moved += 1
                continue
            try:
                folder_path = os.path.dirname(file_path)
                discard_folder = os.path.join(folder_path, "Discard")
                os.makedirs(discard_folder, exist_ok=True)
                filename = os.path.basename(file_path)
                target_path = os.path.join(discard_folder, filename)
                base, ext = os.path.splitext(filename)
                counter = 1
                while os.path.exists(target_path):
                    target_path = os.path.join(
                        discard_folder, f"{base}_discarded_{counter}{ext}"
                    )
                    counter += 1
                self._cancel_load_and_preload_for_path(file_path)
                cache.invalidate_file(file_path)
                os.rename(file_path, target_path)
                self._migrate_visual_rotation_path(file_path, target_path)
                self._drop_discarded_from_semantic_corpus(file_path)
                self._remove_files_from_active_image_list([file_path])
                moved += 1
            except Exception:
                errors += 1
        if moved:
            self.status_bar.showMessage(
                f"Moved {moved} image{'s' if moved != 1 else ''} to Discard"
                + (f" ({errors} failed)" if errors else ""),
            )
            self._after_gallery_bulk_file_removal(anchor_path=anchor)
            self.schedule_save_session_state()

    def _gallery_item_clicked(self, file_path):
        """Handle gallery item click - burst stack, single view, or selection."""
        mods = self._gallery_event_modifiers()
        if self._gallery_has_shift_modifier(mods) and not self._gallery_has_extend_modifier(mods):
            self._gallery_shift_click_selection(file_path)
            return
        if self._gallery_has_extend_modifier(mods):
            self._gallery_toggle_path_selection(file_path)
            return
        if (
            getattr(self, "view_mode", "") == "gallery"
            and not getattr(self, "_burst_group_view_active", False)
            and self._is_burst_grouping_enabled()
        ):
            members = self._burst_members_for_path(file_path)
            if members:
                self._enter_burst_group_view(members, cover=file_path)
                return
        self._clear_gallery_selection()
        # SYNC: Update current file index immediately to prevent navigation jumps
        target = _norm_path(file_path)
        if self.image_files:
            try:
                for i, p in enumerate(self.image_files):
                    if _norm_path(p) == target:
                        self.current_file_index = i
                        break
            except Exception:
                pass
        self.current_file_path = file_path
        
        # Mark that we're loading from gallery view - this will trigger full resolution load
        self._loading_from_gallery = True
        self._gallery_entry_accept_embedded = True
        # Reset the GPU view's OWN fit state BEFORE painting the instant tile:
        # the legacy variables below only cover the QLabel route. If the user
        # left the previous single image zoomed (fit_mode False), the tile
        # paint took set_pixmap's preserve-view branch and treated the NEW
        # image's small gallery tile as a same-content downgrade of the OLD
        # image -- s_new = s_old * old_w/tile_w blew up to ~14x ("clicking a
        # gallery image lands on a zoomed-in view", every image once the
        # stale non-fit state stuck).
        gv = getattr(self, "gpu_view", None)
        if gv is not None:
            gv._fit_mode = True
            gv._zoom_intent_100 = False
        # The canonical clear, not the partial hand-rolled reset below: the
        # PREVIOUS image's zoom-restore state (_restore_zoom_level,
        # _pending_zoom_toggle, _pending_gpu_zoom_point, ...) otherwise
        # re-applies its 100% to the NEWLY clicked image the moment its full
        # buffer lands ("clicking a gallery image zooms to 100%").
        self._clear_all_zoom_state()
        self._paint_instant_preview_for_path(file_path, prefer_gallery=True)

        # CRITICAL: Reset zoom state to fit-to-window when loading from gallery
        # This ensures we don't land on a zoomed-in view
        self.fit_to_window = True
        self.current_zoom_level = 1.0
        self.zoom_center_point = None
        # Clear any pending zoom state
        if hasattr(self, '_pending_zoom'):
            self._pending_zoom = False
        if hasattr(self, '_pending_zoom_restore'):
            self._pending_zoom_restore = False
        if hasattr(self, '_restore_zoom_center'):
            self._restore_zoom_center = None
        if hasattr(self, '_restore_zoom_level'):
            self._restore_zoom_level = None

        # Settle-to-fit guarantee. Multiple independent races have landed a
        # gallery click at 100% (stale-viewport fit misreads, leaked
        # zoom-restore state, late prefetched full-res buffers taking the
        # preserve path); each was fixed, and each time the field found
        # another. This closes the CLASS: shortly after the transition, if
        # the view ended non-fit and the user has not zoomed since (any user
        # zoom sets _zoom_intent_100 or a pending-zoom flag), force fit and
        # log which state needed correcting so the residual path stays
        # visible in logs instead of on screen.
        self._gallery_fit_token = token = object()

        def _enforce_gallery_fit() -> None:
            if getattr(self, "_gallery_fit_token", None) is not token:
                return
            g = getattr(self, "gpu_view", None)
            if g is None or not g.has_pixmap():
                return
            user_zoomed = bool(
                getattr(g, "_zoom_intent_100", False)
                or getattr(self, "_pending_zoom_toggle", False)
                or getattr(self, "_pending_gpu_zoom_point", None) is not None
                or getattr(self, "_pending_zoom", False)
            )
            if user_zoomed or g.is_fit_mode():
                return
            logging.getLogger(__name__).info(
                "[GALLERY_FIT] Correcting non-fit landing after gallery click "
                "(scale=%.4f fit=%.4f) — residual zoom path still active",
                g.current_scale(), g.fit_scale(),
            )
            g.fit_to_window()

        # Two shots only: the transition's own paints land within ~400ms, and
        # a longer window risks undoing a genuine wheel zoom (which sets no
        # intent flag) made right after landing.
        QTimer.singleShot(80, _enforce_gallery_fit)
        QTimer.singleShot(450, _enforce_gallery_fit)

        self.view_mode = 'single'
        if hasattr(self, 'view_mode_button'):
            # Update icon if using qtawesome
            if qta is not None:
                try:
                    gallery_icon = _qta_icon('fa5s.th', color=theme.INK_MUTED)
                    self.view_mode_button.setIcon(gallery_icon)
                    self.view_mode_button.setIconSize(QSize(20, 20))
                    self.view_mode_button.setText("")  # Clear text if using icon
                except Exception:
                    self.view_mode_button.setText("Gallery")
            else:
                self.view_mode_button.setText("Gallery")
        self._show_single_view()
        
        # Reset orientation flag for new load from gallery
        self._orientation_already_applied = False
        
        def _load_gallery_thumbnail(self, file_path, label):
            """Load thumbnail for gallery item asynchronously"""
            # Try to get thumbnail from cache first
            try:
                # Check if we have a cached pixmap
                cached_pixmap = self.image_cache.get_pixmap(file_path)
                if cached_pixmap and not cached_pixmap.isNull():
                    # Scale to fit thumbnail size
                    scaled_pixmap = cached_pixmap.scaled(200, 150, Qt.AspectRatioMode.KeepAspectRatio, Qt.TransformationMode.SmoothTransformation)
                    label.setPixmap(scaled_pixmap)
                    return
                
                # Try to load from file
                if os.path.exists(file_path):
                    # For non-RAW files, use safe loader (handles TIFF properly)
                    file_ext = os.path.splitext(file_path)[1].lower()
                    if file_ext not in ['.arw', '.cr2', '.nef', '.raf', '.orf', '.dng', '.cr3']:
                        pixmap = self._load_pixmap_safe(file_path)
                        if not pixmap.isNull():
                            # Ensure dimensions > 0 (already 200x150 here, but good for safety)
                            scaled_pixmap = pixmap.scaled(200, 150, Qt.AspectRatioMode.KeepAspectRatio, Qt.TransformationMode.SmoothTransformation)
                            label.setPixmap(scaled_pixmap)
                            return
                    
                    # For RAW files, we'll need to extract thumbnail
                    # This is a placeholder - full implementation would use ThumbnailExtractor
                    label.setText("RAW\nLoading...")
            except Exception as e:
                import logging
                logger = logging.getLogger(__name__)
                logger.debug(f"Error loading gallery thumbnail for {file_path}: {e}")
                label.setText("Error")
    
    def _update_sort_button_text(self):
        """Update the sort toggle button text based on current preference"""
        if hasattr(self, 'sort_toggle_button'):
            if self.get_sort_preference():
                self.sort_toggle_button.setText("⇅ Newest")
            else:
                self.sort_toggle_button.setText("⇅ Oldest")
        self._schedule_search_expand_overlay_sync()
    
    def resort_current_folder(self):
        """Resort the current folder with new sorting preference (sort runs off UI thread)."""
        if not self.current_folder or not self.image_files:
            return

        paths = list(self.image_files)
        token = getattr(self, "_folder_resort_generation", 0) + 1
        self._folder_resort_generation = token

        in_gallery = (
            self.view_mode == "gallery"
            and hasattr(self, "gallery_widget")
            and self.gallery_widget.isVisible()
        )
        anchor_file = None
        if in_gallery and hasattr(self, "gallery_justified") and self.gallery_justified:
            anchor_file = self.gallery_justified.get_scroll_anchor_path()

        self._folder_resort_context = {
            "token": token,
            "current_file": self.current_file_path,
            "old_index": self.current_file_index,
            "in_gallery": in_gallery,
            "anchor_file": anchor_file,
        }

        signals = getattr(self, "_folder_resort_signals", None)
        if signals is None:
            signals = FolderResortSignals()
            signals.ready.connect(self._apply_folder_resort)
            self._folder_resort_signals = signals

        viewer = self
        file_stats = getattr(self, "_quick_folder_file_stats", None)
        newest_first = self.get_sort_preference()
        folder_path = self.current_folder

        class _FolderResortWorker(QRunnable):
            def run(self_inner):
                try:
                    sorted_files, bulk_metadata = viewer.sort_files_by_capture_time(
                        paths,
                        newest_first=newest_first,
                        file_stats=file_stats,
                        folder_path=folder_path,
                    )
                except Exception as e:
                    import logging
                    import traceback

                    logging.getLogger(__name__).error(
                        "[SORT] Background folder resort failed: %s\n%s",
                        e,
                        traceback.format_exc(),
                    )
                    sorted_files, bulk_metadata = paths, {}
                try:
                    from PyQt6 import sip

                    if not sip.isdeleted(signals):
                        signals.ready.emit(token, sorted_files, bulk_metadata)
                except Exception:
                    pass

        _get_bg_thread_pool().start(_FolderResortWorker())

    def _apply_folder_resort(self, token: int, sorted_files: list, bulk_metadata: dict) -> None:
        """Apply background folder re-sort on the UI thread."""
        if token != getattr(self, "_folder_resort_generation", None):
            return
        ctx = getattr(self, "_folder_resort_context", None) or {}
        if ctx.get("token") != token:
            return
        if not self.current_folder or not sorted_files:
            return

        current_file = ctx.get("current_file")
        old_index = ctx.get("old_index", 0)
        in_gallery = ctx.get("in_gallery", False)
        anchor_file = ctx.get("anchor_file")

        self.image_files = sorted_files
        self._gallery_bulk_metadata = bulk_metadata
        self._bump_gallery_rating_presence_epoch()

        if current_file in self.image_files:
            self.current_file_index = self.image_files.index(current_file)
            self.current_file_path = current_file

            import logging

            logger = logging.getLogger(__name__)
            logger.debug(f"[SORT] Resorted folder: {os.path.basename(current_file or '')}")
            logger.debug(f"[SORT] Old index: {old_index}, New index: {self.current_file_index}")
            logger.debug(f"[SORT] Total files: {len(self.image_files)}")

            self.update_status_bar()

            if in_gallery:
                self._sync_gallery_to_folder_files(
                    bulk_metadata=bulk_metadata,
                    scroll_to_current=False,
                    scroll_anchor_path=anchor_file or current_file,
                    force=True,
                )

    def get_image_capture_time(self, file_path):
        """Extract image capture time from EXIF data (DateTimeOriginal)"""
        try:
            # Try to get from cache first
            from image_cache import get_image_cache
            cache = get_image_cache()
            cached_exif = cache.get_exif(file_path)
            
            if cached_exif and cached_exif.get('capture_time'):
                from common_image_loader import parse_capture_time_to_timestamp
                ts = parse_capture_time_to_timestamp(cached_exif['capture_time'])
                if ts > 0:
                    return ts
            
            # If not in cache, try to extract from EXIF
            try:
                # Only attempt exifread on formats likely to have compatible EXIF
                # (JPEG, TIFF, and RAW formats)
                ext = os.path.splitext(file_path)[1].lower()
                exif_likely_exts = {'.jpg', '.jpeg', '.tif', '.tiff', '.arw', '.cr2', '.nef', '.raf', '.orf', '.dng', '.cr3'}
                
                if ext in exif_likely_exts:
                    tags = process_file_from_path(file_path, details=False)

                    # Try different datetime tags in order of preference
                    datetime_tags = [
                        "EXIF DateTimeOriginal",
                        "Image DateTime",
                        "EXIF DateTime",
                    ]
                    for tag_name in datetime_tags:
                        if tag_name in tags:
                            datetime_raw = tags[tag_name]
                            try:
                                datetime_str = str(datetime_raw)
                                # Parse datetime string (format: "YYYY:MM:DD HH:MM:SS")
                                dt = datetime.strptime(
                                    datetime_str, "%Y:%m:%d %H:%M:%S"
                                )
                                return dt.timestamp()
                            except (ValueError, AttributeError):
                                continue
            except Exception:
                pass
            
            # Fallback to file modification time if EXIF extraction fails
            try:
                return os.path.getmtime(file_path)
            except (OSError, AttributeError):
                # Last resort: use 0 (will sort to beginning/end depending on order)
                return 0
        except Exception:
            # If all else fails, use file modification time
            try:
                return os.path.getmtime(file_path)
            except (OSError, AttributeError):
                return 0
    
    @staticmethod
    def _mtime_birth_from_file_stats(file_stats, file_path: str) -> tuple:
        """Return (mtime, birthtime) from file_stats row (size, mtime) or (size, mtime, birth)."""
        if not file_stats:
            return 0.0, 0.0
        row = file_stats.get(file_path)
        if row is None:
            nk = _norm_path(file_path)
            for key, val in file_stats.items():
                if _norm_path(key) == nk:
                    row = val
                    break
        if row is None:
            return 0.0, 0.0
        if len(row) >= 3:
            return float(row[1]), float(row[2])
        if len(row) >= 2:
            return float(row[1]), 0.0
        return 0.0, 0.0

    def _parallel_probe_capture_times(
        self,
        file_paths,
        bulk_metadata,
        *,
        sample_path: Optional[str] = None,
        conservative: bool = False,
    ) -> dict:
        """Probe capture timestamps in parallel for all paths not cached in bulk_metadata."""
        missing_paths = []
        for fp in file_paths:
            meta = bulk_metadata.get(fp) if bulk_metadata else None
            if not meta or not meta.get("capture_time"):
                missing_paths.append(fp)

        probed_timestamps: dict = {}
        if not missing_paths:
            return probed_timestamps

        from concurrent.futures import ThreadPoolExecutor
        from common_image_loader import (
            io_pressure_active,
            probe_capture_timestamp_from_file,
            sort_probe_worker_count,
        )
        import logging

        logger = logging.getLogger(__name__)
        hint = sample_path or missing_paths[0]
        conservative = conservative or io_pressure_active() or len(missing_paths) > 400
        workers = sort_probe_worker_count(hint, conservative=conservative)
        chunksize = max(1, len(missing_paths) // max(workers * 8, 1))
        logger.info(
            "[SORT] Probing %d uncached files (%d workers, chunksize=%d, conservative=%s)",
            len(missing_paths),
            workers,
            chunksize,
            conservative,
        )

        def _probe_one(p: str) -> tuple[str, float]:
            try:
                from image_load_manager import get_image_load_manager, Priority
                import time
                manager = get_image_load_manager()
                viewer = self
                # Yield only while arrow-key navigation is in flight so cold
                # folder sort does not steal the disk from the on-screen image.
                # Do NOT wait on PRELOAD_* (idle neighbor prefetch is almost
                # always queued) or on CURRENT once navigation has stopped —
                # full-res CURRENT upgrades stay active for seconds, and a
                # per-file 250ms wait × thousands of files permanently delayed
                # EXIF sort, keeping the Gallery button hidden.
                # Cap: RAWVIEWER_SORT_PROBE_MAX_YIELD_MS (0 = never yield).
                max_yield_ms = _env_int(
                    "RAWVIEWER_SORT_PROBE_MAX_YIELD_MS", 250, minimum=0
                )
                if max_yield_ms > 0:
                    yield_deadline = time.monotonic() + (max_yield_ms / 1000.0)
                    while time.monotonic() < yield_deadline:
                        if not getattr(viewer, "_navigation_in_progress", False):
                            break
                        has_current = False
                        if manager is not None:
                            with manager._queue_lock:
                                for t in manager._active_tasks.values():
                                    if t.is_cancelled():
                                        continue
                                    if getattr(t, "priority", None) == Priority.CURRENT:
                                        has_current = True
                                        break
                        if not has_current:
                            break
                        time.sleep(0.05)
            except Exception:
                pass

            try:
                return p, probe_capture_timestamp_from_file(p)
            except Exception:
                return p, 0.0


        with ThreadPoolExecutor(max_workers=workers) as pool:
            for p, ts in pool.map(_probe_one, missing_paths, chunksize=chunksize):
                if ts > 0:
                    probed_timestamps[p] = ts

        logger.info(
            "[SORT] Probed %d/%d capture timestamps",
            len(probed_timestamps),
            len(missing_paths),
        )

        if probed_timestamps:
            try:
                from image_cache import get_image_cache

                get_image_cache().record_probed_capture_times(probed_timestamps)
            except Exception:
                pass
        return probed_timestamps

    def sort_files_by_capture_time(
        self,
        file_paths,
        newest_first=True,
        file_stats=None,
        *,
        probe_uncached: bool = True,
        folder_path: Optional[str] = None,
        sort_probe_conservative: bool = False,
        capture_time_only: bool = False,
    ):
        """Sort files by capture time according to user preference (Newest/Oldest).

        capture_time_only: read ONLY the capture_time column (via
        get_capture_times_for_sort) instead of the full per-file EXIF blob.
        Sorting needs nothing else, and get_multiple_exif() does a pickle.loads
        of a ~97-tag EXIF dict per file -- on a background sort worker that
        pickle.loads burst holds the GIL and starves the on-screen image's
        decode/paint (measured stalling session-restore first-image display).
        In this mode bulk_metadata is returned EMPTY: the full per-file EXIF
        (gallery tile geometry) is fetched lazily when the gallery is actually
        opened (see the _GalleryMetadataFetch path), and returning {} here
        avoids both clobbering _gallery_bulk_metadata and suppressing that lazy
        fetch.
        """
        import time
        import logging
        logger = logging.getLogger(__name__)
        
        if not file_paths:
            return [], {}

        sort_start = time.time()
        
        # 1. Bulk fetch metadata for all files at once (MUCH faster than individual calls)
        from image_cache import get_image_cache
        cache = get_image_cache()

        # sort_meta holds only what the sort keys need (capture_time); it is what
        # we return as bulk_metadata EXCEPT in capture_time_only mode (see below).
        if capture_time_only:
            ct_map = cache.get_capture_times_for_sort(list(file_paths))
            sort_meta = {
                fp: {"capture_time": ct} for fp, ct in ct_map.items() if ct
            }
        else:
            # Pass the pre-collected file stats to avoid redundant os.stat calls
            sort_meta = cache.get_multiple_exif(file_paths, file_stats)

            # capture_time doesn't depend on RAW_EXIF_SENSOR_META_VER / orientation-trust
            # checks that get_multiple_exif gates the rest of a row on, so a previously
            # probed-and-persisted capture_time (record_probed_capture_times) can still
            # satisfy sorting even when the row it's stored alongside fails those
            # unrelated freshness checks and gets excluded from sort_meta above.
            # Without this, every folder re-open would re-probe the same files forever.
            needs_capture_time = [
                fp for fp in file_paths if not (sort_meta.get(fp) or {}).get("capture_time")
            ]
            if needs_capture_time:
                extra_capture_times = cache.get_capture_times_for_sort(needs_capture_time)
                for fp, ct in extra_capture_times.items():
                    if ct:
                        sort_meta[fp] = {**(sort_meta.get(fp) or {}), "capture_time": ct}

        # 2. Parallel probe for any uncached files (skip when caller only wants cache hits)
        probed_timestamps: dict = {}
        if probe_uncached:
            sample = folder_path
            if not sample and file_paths:
                sample = os.path.dirname(os.path.abspath(file_paths[0]))
            probed_timestamps = self._parallel_probe_capture_times(
                file_paths,
                sort_meta,
                sample_path=sample,
                conservative=sort_probe_conservative,
            )
        
        # 3. Pre-calculate sorting keys to avoid repeated strptime calls
        # This is a MASSIVE optimization for thousands of files
        from common_image_loader import resolve_folder_sort_timestamp

        sort_keys = {}
        for fp in file_paths:
            mtime = 0.0
            if file_stats and fp in file_stats:
                mtime = file_stats[fp][1]
            meta = sort_meta.get(fp) if sort_meta else None
            probed_ts = probed_timestamps.get(fp, 0.0)
            
            _has_capture, timestamp, _source = resolve_folder_sort_timestamp(
                fp,
                metadata=meta,
                file_mtime=mtime,
                probe_file=False,
                probed_capture_timestamp=probed_ts
            )
            sort_keys[fp] = (timestamp, os.path.basename(fp).lower())
        
        # 4. Perform the sort using pre-calculated keys
        sorted_files = sorted(
            file_paths, 
            key=lambda fp: sort_keys[fp],
            reverse=newest_first
        )
        
        sort_time = time.time() - sort_start
        logger.info(
            "[SORT] %s fetch & sort of %d files took %.3fs",
            "Capture-time-only" if capture_time_only else "Bulk metadata",
            len(file_paths),
            sort_time,
        )
        safe_print(f"[PERF] 🔄 Sorted {len(file_paths)} files in {sort_time*1000:.1f}ms")
        # capture_time_only: bulk_metadata is intentionally empty so the gallery
        # lazily fetches full per-file EXIF on first open (see the docstring).
        return sorted_files, ({} if capture_time_only else sort_meta)
    
    def sort_image_files(self, file_paths, file_stats=None):
        """Sort files by capture time according to user preference (Newest/Oldest)"""
        newest_first = self.get_sort_preference()  # True = Newest first, False = Oldest first
        return self.sort_files_by_capture_time(file_paths, newest_first=newest_first, file_stats=file_stats)

    def _sanitize_dialog_start_dir(self, last_dir) -> str:
        """Return an existing directory for QFileDialog, or empty for default location."""
        path = (last_dir or "").strip()
        if not path:
            return ""
        if os.path.isdir(path):
            return path
        parent = os.path.dirname(path)
        if parent and os.path.isdir(parent):
            return parent
        return ""

    def _directory_looks_writable(self, directory: str) -> bool:
        """Best-effort write probe (POSIX permissions / read-only volumes).

        RAWviewer is not App-Sandboxed, so NSSavePanel does not grant extra TCC
        power — export still needs a folder the process can create files in
        (SD cards and camera volumes are often mounted read-only).
        """
        directory = (directory or "").strip()
        if not directory or not os.path.isdir(directory):
            return False
        try:
            if not os.access(directory, os.W_OK):
                return False
        except OSError:
            return False
        probe = None
        try:
            import tempfile

            fd, probe = tempfile.mkstemp(prefix=".rawviewer_wprobe_", dir=directory)
            os.close(fd)
            return True
        except OSError:
            return False
        finally:
            if probe:
                try:
                    os.remove(probe)
                except OSError:
                    pass

    def _preferred_writable_export_dir(self, preferred: str = "") -> str:
        """Pick a writable export folder; fall back to Pictures/Desktop/home."""
        preferred = self._sanitize_dialog_start_dir(preferred)
        if preferred and self._directory_looks_writable(preferred):
            return preferred
        home = os.path.expanduser("~")
        for candidate in (
            os.path.join(home, "Pictures"),
            os.path.join(home, "Desktop"),
            os.path.join(home, "Downloads"),
            home,
        ):
            if self._directory_looks_writable(candidate):
                return candidate
        return preferred or home

    def _export_destination_permission_error(self, output_path: str) -> str | None:
        """Return a user-facing message if output_path cannot be written, else None."""
        output_path = (output_path or "").strip()
        if not output_path:
            return "No export destination was chosen."
        parent = os.path.dirname(os.path.abspath(output_path))
        if not parent:
            return f"Invalid export path:\n{output_path}"
        if not os.path.isdir(parent):
            try:
                os.makedirs(parent, exist_ok=True)
            except OSError as exc:
                return (
                    f"Cannot create export folder:\n{parent}\n\n{exc}\n\n"
                    "Choose Desktop, Pictures, or Downloads instead "
                    "(camera cards / network shares are often read-only)."
                )
        if os.path.exists(output_path) and not os.access(output_path, os.W_OK):
            return (
                f"Cannot overwrite (permission denied):\n{output_path}\n\n"
                "Pick another name or folder."
            )
        if not self._directory_looks_writable(parent):
            return (
                f"Cannot write to this folder (permission denied or read-only volume):\n"
                f"{parent}\n\n"
                "Choose Desktop, Pictures, or Downloads. "
                "SD cards and camera volumes are often mounted read-only."
            )
        return None

    def _use_qt_file_dialog(self) -> bool:
        """Use the native system file picker by default (Windows Explorer-style dialog).

        The cross-platform Qt (DontUseNativeDialog) picker is an OPT-IN fallback:
        set RAWVIEWER_QT_FILE_DIALOG=1 if the native Windows dialog ever crashes
        on a given machine (some shell preview/thumbnail handlers or cloud-storage
        overlays can abort it when it opens over the OpenGL view).
        """
        raw = os.environ.get("RAWVIEWER_QT_FILE_DIALOG", "").strip().lower()
        return raw in {"1", "true", "yes", "on"}

    def _macos_nsopenpanel_reliable(self) -> bool:
        """False when NSOpenPanel/NSSavePanel construction is unsafe to try.

        A bare ``python3 main.py`` Terminal launch (``sys.frozen`` unset --
        no real .app bundle/Info.plist/bundle identifier) was observed via
        py-spy to sometimes hang *indefinitely* inside
        ``NSOpenPanel.alloc().init()`` on newer macOS instead of returning
        nil -- not consistently, so the try/except fallback to AppleScript
        cannot save us; a hang never raises. The built .app (``sys.frozen``
        True) has real bundle identity and does not hit this, so only skip
        NSPanel there when NOT frozen -- go straight to the AppleScript
        dialog, which is reliable everywhere.
        """
        return bool(getattr(sys, "frozen", False))

    def _prepare_for_modal_dialog(self) -> None:
        """Bring the main window forward so native file dialogs are not hidden behind it."""
        try:
            _activate_macos_foreground_app()
            app = _qt_app()
            if app is not None:
                app.setActiveWindow(self)
            self.raise_()
            self.activateWindow()
            if app is not None:
                app.processEvents()
        except Exception:
            pass

    def _create_macos_open_panel(self):
        """Return an NSOpenPanel instance (can fail when Qt owns NSApplication).

        A ``nil`` result here (not an exception) means the window-server /
        open-and-save-panel XPC service refused to hand back a panel --
        which it can do for a process that isn't NSApplicationActivationPolicy
        Regular / frontmost, the default state for a bare ``python3 main.py``
        Terminal launch. A forced-foreground retry was tried here and made
        things worse: forcing activation mid-attempt causes the retried
        alloc().init() to hang indefinitely (observed via py-spy: stuck
        inside this call after activation, never returning nil or raising)
        instead of the plain attempt's fast nil-return -- likely because
        forcing activation kicks off real window-server/XPC machinery that
        needs the run loop pumping, which nothing does on this synchronous
        Qt-thread call stack. Fail fast on the first nil instead so the
        (working) AppleScript fallback in ``_open_file_dialog_macos_native``
        takes over quickly.
        """
        import objc

        ns_open_panel = objc.lookUpClass("NSOpenPanel")
        panel = ns_open_panel.alloc().init()
        if panel is None:
            panel = ns_open_panel.openPanel()
        if panel is None:
            raise RuntimeError("NSOpenPanel could not be created")
        return panel

    def _open_file_dialog_macos_applescript(self, last_dir: str) -> str:
        """Native macOS Finder file picker via AppleScript (works with Qt + Terminal)."""
        types = [
            ext.lstrip(".").lower()
            for ext in self.get_supported_extensions()
            if ext
        ]
        type_clause = ""
        if types:
            type_list = ", ".join(f'"{_applescript_escape(t)}"' for t in types)
            type_clause = f" of type {{{type_list}}}"

        start = self._sanitize_dialog_start_dir(last_dir)
        location_clause = ""
        if start:
            location_clause = (
                f' default location (POSIX file "{_applescript_escape(start)}")'
            )

        # A bare top-level "activate" (no tell-application context) does not
        # reliably bring this dialog forward -- confirmed live: the osascript
        # process was up and running with "activate" in the script, but the
        # picker stayed invisible (no crash, no timeout, just never seen).
        # Running "choose file" inside an explicit `tell application "Finder"`
        # block makes Finder itself own + activate the dialog, which is the
        # reliable form of this trick (Finder is always a proper foreground
        # GUI app, unlike the bare osascript process).
        script = (
            'tell application "Finder"\n'
            "    activate\n"
            f'    choose file{type_clause} with prompt "Open Image"{location_clause}\n'
            "end tell\n"
            "return POSIX path of result"
        )
        return _run_applescript(script)

    def _open_folder_dialog_macos_applescript(self, last_dir: str) -> str:
        start = self._sanitize_dialog_start_dir(last_dir)
        location_clause = ""
        if start:
            location_clause = (
                f' default location (POSIX file "{_applescript_escape(start)}")'
            )
        script = (
            'tell application "Finder"\n'
            "    activate\n"
            f'    choose folder with prompt "Open Folder"{location_clause}\n'
            "end tell\n"
            "return POSIX path of result"
        )
        return _run_applescript(script)

    def _open_file_dialog_macos_native(self, last_dir: str) -> str:
        """Prefer NSOpenPanel; fall back to AppleScript (true Finder UI under Qt)."""
        import logging

        logger = logging.getLogger(__name__)
        if not self._macos_nsopenpanel_reliable():
            logger.info(
                "Skipping NSOpenPanel (unbundled dev launch), using AppleScript choose file"
            )
            return self._open_file_dialog_macos_applescript(last_dir)
        try:
            return self._open_file_dialog_macos_nsopenpanel(last_dir)
        except Exception as exc:
            logger.warning(
                "NSOpenPanel unavailable (%s), using AppleScript choose file",
                exc,
            )
        return self._open_file_dialog_macos_applescript(last_dir)

    def _open_folder_dialog_macos_native(self, last_dir: str) -> str:
        import logging

        logger = logging.getLogger(__name__)
        if not self._macos_nsopenpanel_reliable():
            logger.info(
                "Skipping NSOpenPanel (unbundled dev launch), using AppleScript choose folder"
            )
            return self._open_folder_dialog_macos_applescript(last_dir)
        try:
            return self._open_folder_dialog_macos_nsopenpanel(last_dir)
        except Exception as exc:
            logger.warning(
                "NSOpenPanel unavailable (%s), using AppleScript choose folder",
                exc,
            )
        return self._open_folder_dialog_macos_applescript(last_dir)

    def _open_file_dialog_macos_nsopenpanel(self, last_dir: str) -> str:
        """macOS Finder open panel via AppKit (Qt native QFileDialog fails when run from Terminal)."""
        from AppKit import NSURL

        panel = self._create_macos_open_panel()
        panel.setTitle_("Open Image")
        panel.setPrompt_("Open")
        panel.setCanChooseFiles_(True)
        panel.setCanChooseDirectories_(False)
        panel.setAllowsMultipleSelection_(False)

        types = [ext.lstrip(".").lower() for ext in self.get_supported_extensions()]
        if types:
            panel.setAllowedFileTypes_(types)

        start = self._sanitize_dialog_start_dir(last_dir)
        if start:
            panel.setDirectoryURL_(NSURL.fileURLWithPath_(start))

        if panel.runModal() != 1:  # NSModalResponseOK
            return ""
        url = panel.URL()
        return url.path() if url is not None else ""

    def _open_folder_dialog_macos_nsopenpanel(self, last_dir: str) -> str:
        from AppKit import NSURL

        panel = self._create_macos_open_panel()
        panel.setTitle_("Open Folder")
        panel.setPrompt_("Open")
        panel.setCanChooseFiles_(False)
        panel.setCanChooseDirectories_(True)
        panel.setAllowsMultipleSelection_(False)

        start = self._sanitize_dialog_start_dir(last_dir)
        if start:
            panel.setDirectoryURL_(NSURL.fileURLWithPath_(start))

        if panel.runModal() != 1:
            return ""
        url = panel.URL()
        return url.path() if url is not None else ""

    def _create_macos_save_panel(self):
        """Return an NSSavePanel instance (can fail when Qt owns NSApplication).

        See ``_create_macos_open_panel`` for why this fails fast on a nil
        result instead of retrying with forced foreground activation --
        the retry was observed to hang indefinitely rather than fail fast.
        """
        import objc

        ns_save_panel = objc.lookUpClass("NSSavePanel")
        panel = ns_save_panel.alloc().init()
        if panel is None:
            panel = ns_save_panel.savePanel()
        if panel is None:
            raise RuntimeError("NSSavePanel could not be created")
        try:
            panel.setCanCreateDirectories_(True)
        except Exception:
            pass
        return panel

    def _save_file_dialog_macos_applescript(
        self, default_dir: str, default_name: str, prompt: str
    ) -> str:
        """Native macOS Finder save picker via AppleScript (works with Qt + Terminal)."""
        start = self._sanitize_dialog_start_dir(default_dir)
        location_clause = ""
        if start:
            location_clause = (
                f' default location (POSIX file "{_applescript_escape(start)}")'
            )
        name_clause = ""
        if default_name:
            name_clause = f' default name "{_applescript_escape(default_name)}"'
        script = (
            'tell application "Finder"\n'
            "    activate\n"
            f'    choose file name with prompt "{_applescript_escape(prompt)}"'
            f"{name_clause}{location_clause}\n"
            "end tell\n"
            "return POSIX path of result"
        )
        return _run_applescript(script)

    def _save_file_dialog_macos_nssavepanel(
        self,
        default_dir: str,
        default_name: str,
        prompt: str,
        file_types: list,
    ) -> str:
        """macOS Finder save panel via AppKit (Qt native QFileDialog fails when run from Terminal)."""
        from AppKit import NSURL

        panel = self._create_macos_save_panel()
        panel.setTitle_(prompt)
        panel.setPrompt_("Export")
        if default_name:
            panel.setNameFieldStringValue_(default_name)
        if file_types:
            try:
                panel.setAllowedFileTypes_(file_types)
            except Exception:
                pass

        start = self._sanitize_dialog_start_dir(default_dir)
        if start:
            panel.setDirectoryURL_(NSURL.fileURLWithPath_(start))

        if panel.runModal() != 1:  # NSModalResponseOK
            return ""
        url = panel.URL()
        if url is None:
            return ""
        # Defensive: keep security-scoped access alive for the chosen file URL
        # (harmless when not sandboxed; required if TCC treats the pick specially).
        try:
            url.startAccessingSecurityScopedResource()
        except Exception:
            pass
        try:
            return str(url.path() or "")
        finally:
            # Export writes asynchronously on a worker thread; do not stop
            # access here. macOS releases scope when the process exits; for
            # non-sandboxed apps this is a no-op either way.
            pass

    def _save_file_dialog_macos_native(
        self,
        default_dir: str,
        default_name: str,
        prompt: str,
        file_types: list,
    ) -> str:
        """Prefer NSSavePanel; fall back to AppleScript (true Finder UI under Qt)."""
        import logging

        logger = logging.getLogger(__name__)
        if not self._macos_nsopenpanel_reliable():
            logger.info(
                "Skipping NSSavePanel (unbundled dev launch), using AppleScript choose file name"
            )
            return self._save_file_dialog_macos_applescript(default_dir, default_name, prompt)
        try:
            return self._save_file_dialog_macos_nssavepanel(
                default_dir, default_name, prompt, file_types
            )
        except Exception as exc:
            logger.warning(
                "NSSavePanel unavailable (%s), using AppleScript choose file name",
                exc,
            )
        return self._save_file_dialog_macos_applescript(default_dir, default_name, prompt)

    def _choose_macos_editing_app_applescript(self, start_dir: str) -> str:
        """Native app picker via AppleScript (works when Qt owns NSApplication)."""
        start = self._sanitize_dialog_start_dir(start_dir) or "/Applications"
        location_clause = (
            f' default location (POSIX file "{_applescript_escape(start)}")'
        )
        script = (
            'tell application "Finder"\n'
            "    activate\n"
            '    choose file of type {"com.apple.application-bundle", "app"} '
            f'with prompt "Choose Editing App"{location_clause}\n'
            "end tell\n"
            "return POSIX path of result"
        )
        return _run_applescript(script)

    def _choose_macos_editing_app_nsopenpanel(self, start_dir: str) -> str:
        """macOS app bundle picker via AppKit."""
        from AppKit import NSURL

        panel = self._create_macos_open_panel()
        panel.setTitle_("Choose Editing App")
        panel.setPrompt_("Choose")
        panel.setCanChooseFiles_(True)
        panel.setCanChooseDirectories_(True)
        panel.setAllowsMultipleSelection_(False)
        panel.setTreatsFilePackagesAsDirectories_(True)
        try:
            panel.setAllowedFileTypes_(["app"])
        except Exception:
            pass

        start = self._sanitize_dialog_start_dir(start_dir) or "/Applications"
        panel.setDirectoryURL_(NSURL.fileURLWithPath_(start))

        if panel.runModal() != 1:
            return ""
        url = panel.URL()
        return url.path() if url is not None else ""

    def _choose_macos_editing_app_dialog(self, start_dir: str = "/Applications") -> str:
        """Pick a .app bundle; Qt QFileDialog fails on macOS when launched from Terminal."""
        import logging

        logger = logging.getLogger(__name__)
        if self._use_qt_file_dialog():
            self._prepare_for_modal_dialog()
            app_path, _ = QFileDialog.getOpenFileName(
                self,
                "Choose Editing App",
                start_dir,
                "Applications (*.app);;All Files (*)",
                options=QFileDialog.Option.DontUseNativeDialog,
            )
            return app_path or ""
        if not self._macos_nsopenpanel_reliable():
            logger.info(
                "Skipping NSOpenPanel app chooser (unbundled dev launch), using AppleScript"
            )
            return self._choose_macos_editing_app_applescript(start_dir)
        try:
            return self._choose_macos_editing_app_nsopenpanel(start_dir)
        except Exception as exc:
            logger.warning(
                "NSOpenPanel app chooser unavailable (%s), using AppleScript",
                exc,
            )
        return self._choose_macos_editing_app_applescript(start_dir)

    def open_file(self):
        """Open an image file (and its containing folder).

        Matches GitHub HEAD (d122434): synchronous QFileDialog on the click stack.
        Deferred timers / processEvents() before the panel break macOS NSOpenPanel.
        """
        import logging

        logger = logging.getLogger(__name__)
        settings = self.get_settings()
        last_dir = settings.value("last_opened_dir", "")

        exts = self.get_supported_extensions()
        input_exts = " ".join([f"*{e}" for e in exts])
        filter_str = f"Images ({input_exts});;All Files (*)"

        try:
            if self._use_qt_file_dialog():
                file_path, _ = QFileDialog.getOpenFileName(
                    self,
                    "Open File",
                    last_dir,
                    filter_str,
                    options=QFileDialog.Option.DontUseNativeDialog,
                )
            elif sys.platform == "darwin":
                file_path = self._open_file_dialog_macos_native(last_dir)
            else:
                self._prepare_for_modal_dialog()
                file_path, _ = QFileDialog.getOpenFileName(
                    self, "Open File", last_dir, filter_str
                )
        except Exception as e:
            logger.error("Open image dialog failed: %s", e, exc_info=True)
            self.show_error("Open Image", f"Could not open file chooser:\n{e}")
            return

        if os.environ.get("RAWVIEWER_DEBUG", "").strip() == "1":
            if self._use_qt_file_dialog():
                backend = "qt"
            elif sys.platform == "darwin":
                backend = "macos-native"
            else:
                backend = "qfiledialog"
            logger.info(
                "Open image dialog done (backend=%s, selected=%r)",
                backend,
                file_path or "",
            )

        if file_path:
            folder_path = os.path.dirname(file_path)
            base = os.path.basename(file_path)
            self.load_folder_images(
                folder_path, start_file=base, start_view="single"
            )
            settings.setValue("last_opened_dir", folder_path)

    def open_folder(self):
        settings = self.get_settings()
        last_dir = settings.value("last_opened_dir", "")
        if self._use_qt_file_dialog():
            folder_path = QFileDialog.getExistingDirectory(
                self,
                "Open Folder",
                last_dir,
                options=QFileDialog.Option.DontUseNativeDialog,
            )
        elif sys.platform == "darwin":
            folder_path = self._open_folder_dialog_macos_native(last_dir)
        else:
            self._prepare_for_modal_dialog()
            folder_path = QFileDialog.getExistingDirectory(
                self, "Open Folder", last_dir
            )
        if folder_path:
            self.load_folder_images(folder_path)
            settings.setValue("last_opened_dir", folder_path)

    def _format_shortcut_line_html(self, line: str) -> str:
        """Bold the shortcut keyword before the em dash for quick scanning."""
        line = line.strip()
        if " — " in line:
            key, desc = line.split(" — ", 1)
            return f"<b>{key.strip()}</b> — {desc.strip()}"
        return f"<b>{line}</b>"

